/**
 * Business Security Settings Page
 * 
 * Manages security settings for business users including password changes,
 * security PIN setup, two-factor authentication, and verification status
 * display for email and phone numbers.
 */

import React, { useEffect, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { authService, tokenService } from '@/features/auth/services';
import { securityService } from '@/features/settings/services';
import { ProfileUtils } from '@/features/settings/utils/profile-utils.js';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { createPinSchema, createPasswordChangeSchema } from '@/shared/utils/validation/settingsSchemas.js';
import { mapFieldErrors } from '@/shared/utils/validation/helpers.js';
import { PasswordRequirements } from '@/shared/components';
import ConfirmDisable2FAModal from '@/features/settings/components/ConfirmDisable2FAModal.jsx';
import logger from '@/shared/utils/logger.js';
import TwoFactorSetupModal from '../../components/TwoFactorSetupModal';

const Security = () => {
  const { t } = useTranslation();
  const { success, error } = useToast();
  const [loading, setLoading] = useState(false);
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmNewPassword, setConfirmNewPassword] = useState('');
  const [passwordMessage, setPasswordMessage] = useState('');
  const [passwordErrors, setPasswordErrors] = useState({});
  const [showCurrentPassword, setShowCurrentPassword] = useState(false);
  const [showNewPassword, setShowNewPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [pinSet, setPinSet] = useState(false);
  const [emailVerified, setEmailVerified] = useState(false);
  const [phoneVerified, setPhoneVerified] = useState(false);

  const [twoFactorEnabled, setTwoFactorEnabled] = useState(() => {
    return localStorage.getItem('twoFactorEnabled') === 'true';
  });

  const [twoFactorSetup, setTwoFactorSetup] = useState({
    step: 1,
    secret: '',
    qrCode: '',
    verificationCode: '',
    loading: false,
    error: ''
  });
  const [showDisable2FAModal, setShowDisable2FAModal] = useState(false);
  const [show2FAModal, setShow2FAModal] = useState(false);
  const [isConfirmingScanned, setIsConfirmingScanned] = useState(false);
  const [windowWidth, setWindowWidth] = useState(typeof window !== 'undefined' ? window.innerWidth : 1024);

  const isMobile = windowWidth <= 768;
  const isTablet = windowWidth > 768 && windowWidth <= 1024;

  const handlePasswordChange = async () => {
    const schema = createPasswordChangeSchema(t);
    const validation = schema.safeParse({
      currentPassword,
      newPassword,
      confirmNewPassword,
    });

    if (!validation.success) {
      const errors = mapFieldErrors(validation.error);
      setPasswordErrors(errors);
      const message = Object.values(errors)[0] || t('pleaseFillAllPasswordFields', { ns: 'settings' });
      error(message);
      setPasswordMessage(message);
      return;
    }

    setPasswordErrors({});
    setPasswordMessage('');

    setLoading(true);

    try {
      await authService.changePassword(currentPassword, newPassword);

      success(t('passwordChangedSuccessfullyLoggingOut', { ns: 'settings' }));
      setPasswordMessage(t('passwordChangedSuccessfullyLoggingOut', { ns: 'settings' }));

      setCurrentPassword('');
      setNewPassword('');
      setConfirmNewPassword('');
      setPasswordErrors({});

      // Logout after a short delay
      setTimeout(async () => {
        await tokenService.safeLogout();
        window.location.href = '/login';
      }, 2000);

    } catch (err) {
      let errorMessage = err?.message || t('networkError', { ns: 'auth' });
      
      // Improve error message for incorrect old password
      if (errorMessage === 'Old password is incorrect') {
        errorMessage = 'The old password you entered is incorrect. Please try again.';
      }
      
      error(errorMessage);
      setPasswordMessage(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  // Use React Query mutation for 2FA disable
  const disable2FAMutation = useMutation({
    mutationFn: async () => {
      return await securityService.disable2FA();
    },
    invalidateQueries: [
      queryKeys.settings.security(),
      queryKeys.settings.all(),
    ],
    onSuccess: () => {
      setTwoFactorEnabled(false);
      localStorage.setItem('twoFactorEnabled', 'false');
      success(t('twoFactorDisabledSuccessfully', { ns: 'settings' }));
    },
    onError: (error) => {
      error(error.message || t('failedToDisable2FA', { ns: 'settings' }));
    },
  });

  const handleToggleTwoFactor = async (e) => {
    // Prevent the click that opens the modal from immediately closing it
    // via any overlay click handlers / delegated events.
    e?.preventDefault?.();
    e?.stopPropagation?.();

    if (twoFactorEnabled) {
      // Defer opening to next tick for stability in portals
      setTimeout(() => setShowDisable2FAModal(true), 0);
    } else {
      handleSetupTwoFactor();
    }
  };

  const handleConfirmDisable2FA = () => {
    disable2FAMutation.mutate();
  };

  const handleSetupTwoFactor = async () => {
    setTwoFactorSetup({ ...twoFactorSetup, loading: true, error: '' });

    try {
      const response = await securityService.enable2FA();

      if (response && response.data) {
        setTwoFactorSetup({
          step: 2,
          secret: response.data.secret,
          qrCode: response.data.qrCode,
          verificationCode: '',
          loading: false,
          error: ''
        });
        setShow2FAModal(true);
      } else {
        setTwoFactorSetup({
          ...twoFactorSetup,
          loading: false,
          error: t('failedToStart2FASetup', { ns: 'settings' })
        });
      }
    } catch (error) {
      const errorMessage = error.message || t('unexpectedError', { ns: 'common' });
      const isAuthError = errorMessage.includes('401') || errorMessage.includes('Unauthorized') || errorMessage.includes('authentication') || errorMessage.includes('Refresh failed');

      setTwoFactorSetup({
        ...twoFactorSetup,
        loading: false,
        error: isAuthError
          ? t('authenticationFailedLogout', { ns: 'common' })
          : errorMessage
      });
    }
  };



  const handleConfirmQRScanned = async () => {
    setIsConfirmingScanned(true);

    try {
      setTwoFactorEnabled(true);
      localStorage.setItem('twoFactorEnabled', 'true');
      success('Two-factor authentication is now enabled! For your security, you will be logged out.');
    } catch (error) {
      error(error.message || 'Failed to update 2FA status.');
    } finally {
      setIsConfirmingScanned(false);
    }
  };

  // Load account security data on page load to show current status
  const [securityDataLoaded, setSecurityDataLoaded] = useState(false);

  const loadSecurityData = async () => {
    if (securityDataLoaded) { return; }

    try {
      const resp = await securityService.getAccountSecurity();
      const sec = resp?.data || {};
      logger.debug('Business account security response', { response: resp, securityData: sec });

      // Check if PIN is set by looking for pin field and it not being null/undefined
      const isPinSet = !!(sec.pinSet || sec.hasPin || sec.has_pin || (sec.pin && sec.pin !== null && sec.pin !== 'null'));
      logger.debug('Business PIN status from API', { isPinSet });
      setPinSet(isPinSet);

      // Check if email is verified
      const isEmailVerified = !!(sec.emailVerified || sec.email_verified === true || sec.email_verified === 'true');
      logger.debug('Business email verification status', { isEmailVerified });
      setEmailVerified(isEmailVerified);

      // Check if phone is verified
      const isPhoneVerified = !!(sec.phoneVerified || sec.phone_verified === true || sec.phone_verified === 'true');
      logger.debug('Business phone verification status', { isPhoneVerified });
      setPhoneVerified(isPhoneVerified);

      // Check multiple possible field names for 2FA status
      const twoFAValue = sec.two_fa_enabled ?? sec.twoFactorEnabled ?? sec.has_2fa ?? sec.twoFaEnabled ?? sec.is2FAEnabled;
      if (twoFAValue !== null && twoFAValue !== undefined && typeof twoFAValue === 'boolean') {
        const enabled = !!twoFAValue;
        logger.debug('Business 2FA enabled status from API', { enabled });
        setTwoFactorEnabled(enabled);
        localStorage.setItem('twoFactorEnabled', String(enabled));
      } else {
        logger.warn('No 2FA status found in business API response');
        // Fallback: check localStorage
        const stored2FA = localStorage.getItem('twoFactorEnabled') === 'true';
        logger.debug('Using stored Business 2FA status from localStorage', { stored2FA });
        setTwoFactorEnabled(stored2FA);
      }

      setSecurityDataLoaded(true);
    } catch (e) {
      logger.error('Error fetching business account security', { error: e });
      // Fallback: check localStorage
      const stored2FA = localStorage.getItem('twoFactorEnabled') === 'true';
      if (stored2FA) {
        logger.debug('Using stored Business 2FA status (after error)', { stored2FA });
        setTwoFactorEnabled(stored2FA);
      }
    }
  };

  // Load security data when component mounts
  useEffect(() => {
    loadSecurityData();
  }, []);

  // Listen for auth state changes (login/logout)
  useEffect(() => {
    const handleAuthStateChange = () => {
      const stored2FA = localStorage.getItem('twoFactorEnabled') === 'true';
      logger.debug('Business auth state changed, updating 2FA status', { stored2FA });
      setTwoFactorEnabled(stored2FA);
    };

    window.addEventListener('authStateChanged', handleAuthStateChange);
    return () => {
      window.removeEventListener('authStateChanged', handleAuthStateChange);
    };
  }, []);

  // Handle window resize for responsive design
  useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      // Debounce resize events to prevent excessive re-renders
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
      resizeTimer = setTimeout(() => {
        setWindowWidth(window.innerWidth);
      }, 100);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
    };
  }, []);

  // PIN form state
  const [pinForm, setPinForm] = useState({ password: '', pin: '', confirm: '', loading: false, error: '', success: '' });
  const [passwordVerified, setPasswordVerified] = useState(false);

  const handleVerifyPassword = async () => {
    if (!pinForm.password || pinForm.password.trim().length === 0) {
      const errorMsg = t('passwordRequired', { ns: 'settings', defaultValue: 'Password is required' });
      setPinForm((prev) => ({ ...prev, error: errorMsg, success: '' }));
      return;
    }
    setPinForm((prev) => ({ ...prev, loading: true, error: '', success: '' }));
    try {
      // Get user email from localStorage
      const userData = JSON.parse(localStorage.getItem('userData') || '{}');
      const email = userData?.email || userData?.user?.email;

      if (!email) {
        throw new Error('Email not found. Please log in again.');
      }

      // Verify password by attempting login and store the new tokens
      const loginResponse = await authService.login(email, pinForm.password);

      // Store the new tokens from login response to ensure PIN set request uses a valid token
      if (loginResponse?.data?.tokens) {
        const tokens = loginResponse.data.tokens;
        if (tokens.accessToken) {
          localStorage.setItem('authToken', tokens.accessToken);
          localStorage.setItem('tokenExpiry', Date.now() + (24 * 60 * 60 * 1000));
        }
        if (tokens.refreshToken) {
          localStorage.setItem('refreshToken', tokens.refreshToken);
        }
      }

      setPasswordVerified(true);
      setPinForm((prev) => ({ ...prev, loading: false, error: '', password: '' }));
    } catch (e) {
      const errorMessage = e?.message || t('incorrectPassword', { ns: 'settings', defaultValue: 'Incorrect password' });
      const lowerMessage = errorMessage.toLowerCase();

      // Check if account is locked or attempts exhausted
      if (lowerMessage.includes('account locked') || lowerMessage.includes('locked') ||
        lowerMessage.includes('attempts exhausted') || lowerMessage.includes('too many attempts')) {
        const lockoutMsg = t('accountLockedLogout', { ns: 'settings', defaultValue: 'Account locked due to too many failed attempts. You will be logged out.' });
        error(lockoutMsg);
        setPinForm((prev) => ({ ...prev, loading: false, error: lockoutMsg, password: '' }));

        // Logout user if account is locked
        setTimeout(async () => {
          await tokenService.safeLogout();
          window.location.href = '/login';
        }, 2000);
      } else {
        error(errorMessage);
        setPinForm((prev) => ({ ...prev, loading: false, error: errorMessage, password: '' }));
      }
      setPasswordVerified(false);
    }
  };

  const handleSetPin = async () => {
    // If PIN is already set, verify password first
    if (pinSet && !passwordVerified) {
      await handleVerifyPassword();
      return;
    }

    const pinSchema = createPinSchema(t);
    const validation = pinSchema.safeParse({
      pin: pinForm.pin,
      confirm: pinForm.confirm,
    });

    if (!validation.success) {
      const errors = mapFieldErrors(validation.error);
      const message = Object.values(errors)[0] || t('pinMustBe4Digits', { ns: 'settings' });
      error(message);
      setPinForm({ ...pinForm, error: message, success: '' });
      return;
    }
    setPinForm({ ...pinForm, loading: true, error: '', success: '' });
    try {
      await securityService.setSecurityPIN(pinForm.pin);
      setPinSet(true);
      setPasswordVerified(false);
      const successMsg = pinSet ? t('pinUpdated', { ns: 'settings', defaultValue: 'PIN updated successfully' }) : t('pinSet', { ns: 'settings' });
      success(successMsg);
      setPinForm({ password: '', pin: '', confirm: '', loading: false, error: '', success: successMsg });
    } catch (e) {
      const errorMessage = e?.message || 'Failed to set PIN';
      error(errorMessage);
      setPinForm({ ...pinForm, loading: false, error: errorMessage, success: '' });
    }
  };


  return (
    <div className="invoices-card">
      <div className="card-head">
        <h3>{t('security', { ns: 'settings' })}</h3>
      </div>
      <div style={{ padding: '20px' }}>

        {/* Two-Factor Authentication */}
        <div data-tour="settings-security-2fa" style={{ marginBottom: '32px', padding: '24px 32px', backgroundColor: 'var(--bg-tertiary)', borderRadius: '12px', border: '1px solid var(--border-primary)' }}>
          <h4 style={{ marginBottom: '16px', color: 'var(--text-primary)', display: 'flex', alignItems: 'center', gap: '8px', fontSize: '1.25rem', fontWeight: '700', letterSpacing: '0.01em' }}>
            <span className="material-symbols-outlined" style={{ fontSize: 24, color: 'var(--accent)' }}>security</span>
            {t('twoFactorAuthentication', { ns: 'settings' })}
          </h4>

          <div style={{ marginBottom: '24px' }}>
            <p style={{ color: 'var(--text-secondary)', marginBottom: '12px', display: 'flex', alignItems: 'center', gap: '8px', fontSize: '1.05rem', fontWeight: '600' }}>
              {t('status', { ns: 'settings' })}: {twoFactorEnabled ? (
                <span style={{ color: 'var(--success)', display: 'flex', alignItems: 'center', gap: '6px' }}>
                  <span className="material-symbols-outlined" style={{ fontSize: 20 }}>verified</span>
                  {t('enabled', { ns: 'settings' })}
                </span>
              ) : (
                <span style={{ color: 'var(--warning)', display: 'flex', alignItems: 'center', gap: '6px' }}>
                  <span className="material-symbols-outlined" style={{ fontSize: 20 }}>shutter_speed</span>
                  {t('disabled', { ns: 'settings' })}
                </span>
              )}
            </p>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.95rem', lineHeight: '1.6' }}>
              {t('twoFactorDescription', { ns: 'settings' })}
            </p>
          </div>

          <div className="verification-btn-group">
            <button
              onClick={handleToggleTwoFactor}
              className={`verification-action-btn ${twoFactorEnabled ? 'secondary' : 'primary'}`}
              style={twoFactorEnabled ? {
                color: 'var(--error, #dc2626)',
                borderColor: 'var(--error, #dc2626)'
              } : {}}
            >
              {twoFactorEnabled ? (
                <>
                  <span className="material-symbols-outlined">lock_reset</span>
                  {t('disable2FAButton', { ns: 'settings' })}
                </>
              ) : (
                <>
                  <span className="material-symbols-outlined">bolt</span>
                  {t('enable2FAButton', { ns: 'settings' })}
                </>
              )}
            </button>
          </div>
        </div>

        {/* 2FA Setup Error */}
        {twoFactorSetup.error && (
          <p style={{ color: 'var(--error)', fontSize: '14px', marginTop: '8px' }}>
            {twoFactorSetup.error}
          </p>
        )}




        {/* Account Security Summary */}
        <div data-tour="settings-security-summary" style={{ marginBottom: '32px', padding: '24px 32px', backgroundColor: 'var(--bg-tertiary)', borderRadius: '12px', border: '1px solid var(--border-primary)' }}>
          <h4 style={{ marginBottom: '16px', color: 'var(--text-primary)', display: 'flex', alignItems: 'center', gap: '8px', fontSize: '1.25rem', fontWeight: '700', letterSpacing: '0.01em' }}>
            <span className="material-symbols-outlined" style={{ fontSize: 24, color: 'var(--accent)' }}>shield_lock</span>
            {t('accountSecurity', { ns: 'settings' })}
          </h4>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            <div className="security-status-card" style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '12px', backgroundColor: 'var(--card)', borderRadius: '8px', border: '1px solid var(--border-primary)' }}>
              <span className="material-symbols-outlined" style={{ fontSize: 24, color: pinSet ? 'var(--success)' : 'var(--text-muted)' }}>
                {pinSet ? 'lock' : 'lock_open'}
              </span>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: '1.05rem', fontWeight: '700', color: 'var(--text-primary)', letterSpacing: '0.01em' }}>{t('securityPin', { ns: 'settings' })}</div>
                <div style={{ fontSize: '0.9rem', color: 'var(--text-muted)', lineHeight: '1.4' }}>{pinSet ? t('pinConfigured', { ns: 'settings' }) : t('pinNotConfigured', { ns: 'settings' })}</div>
              </div>
              <span className="security-status-badge" style={{
                padding: '4px 12px',
                borderRadius: '12px',
                fontSize: '12px',
                fontWeight: '600',
                backgroundColor: pinSet ? 'var(--success-bg)' : 'var(--bg-tertiary)',
                color: pinSet ? 'var(--success)' : 'var(--text-muted)'
              }}>
                {pinSet ? t('set', { ns: 'settings' }) : t('notSet', { ns: 'settings' })}
              </span>
            </div>
            <div className="security-status-card" style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '12px', backgroundColor: 'var(--card)', borderRadius: '8px', border: '1px solid var(--border-primary)' }}>
              <span className="material-symbols-outlined" style={{ fontSize: 24, color: twoFactorEnabled ? 'var(--success)' : 'var(--text-muted)' }}>
                {twoFactorEnabled ? 'verified' : 'security'}
              </span>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: '1.05rem', fontWeight: '700', color: 'var(--text-primary)', letterSpacing: '0.01em' }}>{t('twoFactorAuth', { ns: 'settings' })}</div>
                <div style={{ fontSize: '0.9rem', color: 'var(--text-muted)', lineHeight: '1.4' }}>{twoFactorEnabled ? t('extraSecurityEnabled', { ns: 'settings' }) : t('notEnabled', { ns: 'settings' })}</div>
              </div>
              <span className="security-status-badge" style={{
                padding: '4px 12px',
                borderRadius: '12px',
                fontSize: '12px',
                fontWeight: '600',
                backgroundColor: twoFactorEnabled ? 'var(--success-bg)' : 'var(--error-bg)',
                color: twoFactorEnabled ? 'var(--success)' : 'var(--error)'
              }}>
                {twoFactorEnabled ? t('enabled', { ns: 'settings' }) : t('disabled', { ns: 'settings' })}
              </span>
            </div>
          </div>
        </div>

        {/* Set/Update Security PIN */}
        <div data-tour="settings-security-pin" style={{ marginBottom: '32px', padding: '24px 32px', backgroundColor: 'var(--bg-tertiary)', borderRadius: '12px', border: '1px solid var(--border-primary)' }}>
          <h4 style={{ marginBottom: '12px', color: 'var(--text-primary)', fontSize: '1.25rem', fontWeight: '700', letterSpacing: '0.01em' }}>{pinSet ? t('changeSecurityPin', { ns: 'settings', defaultValue: 'Change Security PIN' }) : t('setSecurityPin', { ns: 'settings' })}</h4>
          {pinSet && (
            <p style={{ fontSize: '0.95rem', color: 'var(--text-muted)', marginBottom: '16px', lineHeight: '1.6', letterSpacing: '0.01em' }}>
              {t('changePinDescription', { ns: 'settings', defaultValue: 'To change your security PIN, first verify your login password, then enter your new 4-digit PIN.' })}
            </p>
          )}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', maxWidth: '280px' }}>
            {/* Show password field if PIN is already set */}
            {pinSet && !passwordVerified && (
              <>
                <div className="input-wrapper">
                  <span className="input-icon"><i className="fa-solid fa-key"></i></span>
                  <input
                    type="password"
                    placeholder={t('enterPassword', { ns: 'settings', defaultValue: 'Enter your password' })}
                    value={pinForm.password}
                    onChange={(e) => {
                      setPinForm((prev) => ({
                        ...prev,
                        password: e.target.value,
                        error: '',
                        success: '',
                      }));
                    }}
                    style={{ marginBottom: 0 }}
                  />
                </div>
                <p style={{
                  fontSize: '12px',
                  color: 'var(--text-muted)',
                  marginTop: '8px',
                  marginBottom: '8px'
                }}>
                  {t('passwordVerificationWarning', { ns: 'settings', defaultValue: 'Note: Failed password attempts may result in account lockout.' })}
                </p>
              </>
            )}

            {/* Show new PIN fields only if PIN is not set, or password is verified */}
            {(!pinSet || passwordVerified) && (
              <>
                <div className="input-wrapper">
                  <span className="input-icon"><i className="fa-solid fa-key"></i></span>
                  <input
                    type="password"
                    inputMode="numeric"
                    pattern="\\d{4}"
                    maxLength={4}
                    placeholder={t('enter4DigitPin', { ns: 'settings' })}
                    value={pinForm.pin}
                    onChange={(e) => {
                      const pin = e.target.value.replace(/[^0-9]/g, '');
                      setPinForm((prev) => ({
                        ...prev,
                        pin,
                        error: '',
                        success: '',
                      }));
                    }}
                    style={{ marginBottom: 0 }}
                  />
                </div>
                <div className="input-wrapper">
                  <span className="input-icon"><i className="fa-solid fa-key"></i></span>
                  <input
                    type="password"
                    inputMode="numeric"
                    pattern="\\d{4}"
                    maxLength={4}
                    placeholder={t('confirm4DigitPin', { ns: 'settings' })}
                    value={pinForm.confirm}
                    onChange={(e) => {
                      const confirm = e.target.value.replace(/[^0-9]/g, '');
                      setPinForm((prev) => ({
                        ...prev,
                        confirm,
                        error: '',
                        success: '',
                      }));
                    }}
                    style={{ marginBottom: 0 }}
                  />
                </div>
              </>
            )}

            {pinForm.error && <p style={{ color: 'var(--error)', fontSize: '14px' }}>{pinForm.error}</p>}
            {pinForm.success && <p style={{ color: 'var(--success)', fontSize: '14px' }}>{pinForm.success}</p>}
            <button
              onClick={handleSetPin}
              disabled={
                (pinSet && !passwordVerified && (pinForm.loading || !pinForm.password.trim())) ||
                ((!pinSet || passwordVerified) && (pinForm.loading || pinForm.pin.length !== 4 || pinForm.confirm.length !== 4))
              }
              style={{
                padding: '10px 20px',
                backgroundColor: (
                  (pinSet && !passwordVerified && (pinForm.loading || !pinForm.password.trim())) ||
                  ((!pinSet || passwordVerified) && (pinForm.loading || pinForm.pin.length !== 4 || pinForm.confirm.length !== 4))
                ) ? 'var(--text-muted)' : 'var(--accent)',
                color: 'var(--text-inverse)',
                border: 'none',
                borderRadius: '6px',
                cursor: (
                  (pinSet && !passwordVerified && (pinForm.loading || !pinForm.password.trim())) ||
                  ((!pinSet || passwordVerified) && (pinForm.loading || pinForm.pin.length !== 4 || pinForm.confirm.length !== 4))
                ) ? 'not-allowed' : 'pointer',
                fontSize: '14px'
              }}
            >
              {pinSet && !passwordVerified
                ? (pinForm.loading ? t('verifying', { ns: 'settings', defaultValue: 'Verifying...' }) : t('verifyPassword', { ns: 'settings', defaultValue: 'Verify Password' }))
                : (pinForm.loading ? t('saving', { ns: 'settings' }) : (pinSet ? t('updatePin', { ns: 'settings' }) : t('setPin', { ns: 'settings' })))
              }
            </button>
          </div>
        </div>

        <div data-tour="settings-security-password">
          <h4 style={{ marginBottom: '16px', color: 'var(--text-primary)' }}>{t('changePassword', { ns: 'settings' })}</h4>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', maxWidth: '400px' }}>
            <div className="input-wrapper" style={{ position: 'relative' }}>
              <span className="input-icon"><i className="fa-solid fa-key"></i></span>
              <input
                type={showCurrentPassword ? 'text' : 'password'}
                placeholder={t('currentPassword', { ns: 'settings' })}
                value={currentPassword}
                onChange={(e) => {
                  setCurrentPassword(e.target.value);
                  if (passwordErrors.currentPassword) {
                    setPasswordErrors((prev) => {
                      const next = { ...prev };
                      delete next.currentPassword;
                      return next;
                    });
                  }
                }}
                style={{ marginBottom: 0, paddingRight: '40px' }}
              />
              <button
                type="button"
                onClick={() => setShowCurrentPassword(!showCurrentPassword)}
                style={{
                  position: 'absolute',
                  right: '10px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  color: 'var(--text-muted)',
                  cursor: 'pointer',
                  padding: '4px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}
                aria-label={showCurrentPassword ? 'Hide password' : 'Show password'}
              >
                <i className={`fa-solid ${showCurrentPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
              </button>
            </div>
            {passwordErrors.currentPassword && (
              <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-8px', marginBottom: '16px' }}>
                {passwordErrors.currentPassword}
              </p>
            )}

            <div className="input-wrapper" style={{ position: 'relative' }}>
              <span className="input-icon"><i className="fa-solid fa-key"></i></span>
              <input
                type={showNewPassword ? 'text' : 'password'}
                placeholder={t('newPassword', { ns: 'settings' })}
                value={newPassword}
                onChange={(e) => {
                  setNewPassword(e.target.value);
                  if (passwordErrors.newPassword) {
                    setPasswordErrors((prev) => {
                      const next = { ...prev };
                      delete next.newPassword;
                      return next;
                    });
                  }
                }}
                style={{ marginBottom: 0, paddingRight: '40px' }}
              />
              <button
                type="button"
                onClick={() => setShowNewPassword(!showNewPassword)}
                style={{
                  position: 'absolute',
                  right: '10px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  color: 'var(--text-muted)',
                  cursor: 'pointer',
                  padding: '4px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}
                aria-label={showNewPassword ? 'Hide password' : 'Show password'}
              >
                <i className={`fa-solid ${showNewPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
              </button>
            </div>
            <PasswordRequirements password={newPassword} />
            {passwordErrors.newPassword && (
              <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '8px', marginBottom: '16px' }}>
                {passwordErrors.newPassword}
              </p>
            )}

            <div className="input-wrapper" style={{ position: 'relative' }}>
              <span className="input-icon"><i className="fa-solid fa-key"></i></span>
              <input
                type={showConfirmPassword ? 'text' : 'password'}
                placeholder={t('confirmNewPassword', { ns: 'settings' })}
                value={confirmNewPassword}
                onChange={(e) => {
                  setConfirmNewPassword(e.target.value);
                  if (passwordErrors.confirmNewPassword) {
                    setPasswordErrors((prev) => {
                      const next = { ...prev };
                      delete next.confirmNewPassword;
                      return next;
                    });
                  }
                }}
                style={{ marginBottom: 0, paddingRight: '40px' }}
              />
              <button
                type="button"
                onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                style={{
                  position: 'absolute',
                  right: '10px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  color: 'var(--text-muted)',
                  cursor: 'pointer',
                  padding: '4px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}
                aria-label={showConfirmPassword ? 'Hide password' : 'Show password'}
              >
                <i className={`fa-solid ${showConfirmPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
              </button>
            </div>
            {passwordErrors.confirmNewPassword && (
              <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-8px', marginBottom: '16px' }}>
                {passwordErrors.confirmNewPassword}
              </p>
            )}

            <button
              onClick={handlePasswordChange}
              disabled={loading}
              style={{
                padding: '10px 20px',
                backgroundColor: 'var(--accent)',
                color: 'white',
                border: 'none',
                borderRadius: '8px',
                cursor: loading ? 'not-allowed' : 'pointer',
                opacity: loading ? 0.7 : 1
              }}
            >
              {loading ? t('changingPassword', { ns: 'settings', defaultValue: 'Changing Password...' }) : t('changePassword', { ns: 'settings' })}
            </button>

            {passwordMessage && (
              <p style={{
                color: passwordMessage.includes('success') ? 'var(--success)' : 'var(--error)',
                fontSize: '14px',
                marginTop: '8px'
              }}>
                {passwordMessage}
              </p>
            )}
          </div>
        </div>

      </div>

      {/* Confirm Disable 2FA Modal */}
      <ConfirmDisable2FAModal
        open={showDisable2FAModal}
        onClose={() => setShowDisable2FAModal(false)}
        onConfirm={handleConfirmDisable2FA}
      />

      {/* 2FA Setup Modal */}
      <TwoFactorSetupModal
        isOpen={show2FAModal}
        onClose={() => setShow2FAModal(false)}
        qrCode={twoFactorSetup.qrCode}
        secret={twoFactorSetup.secret}
        onConfirmScanned={handleConfirmQRScanned}
        isConfirming={isConfirmingScanned}
      />
    </div>
  );
};

export default Security;
