/**
 * Charge Bearer Settings
 *
 * Allows a business to choose who bears transaction charges:
 * the business itself or the customer.
 *
 * Endpoints:
 *   GET  /api/auth/charge-bearer  — fetch current setting
 *   POST /api/auth/charge-bearer  — update setting { charge_bearer: 'business'|'customer' }
 */

import React, { useEffect, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { businessService } from '@/features/settings/services';
import { useToast } from '@/app/providers/ToastContext.jsx';
import logger from '@/shared/utils/logger.js';

const OPTION_BUSINESS = 'business';
const OPTION_CUSTOMER = 'customer';

const ChargeBearer = () => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();

  const [currentBearer, setCurrentBearer] = useState(null); // 'business' | 'customer' | null
  const [selected, setSelected]           = useState(null);
  const [loading, setLoading]             = useState(true);
  const [saving, setSaving]               = useState(false);
  const [fetchError, setFetchError]       = useState('');

  /* ── fetch current setting ──────────────────────────────────── */
  useEffect(() => {
    const load = async () => {
      setLoading(true);
      setFetchError('');
      try {
        const res  = await businessService.getChargeBearer();
        let bearer = res?.data?.bearer ?? res?.bearer ?? null;
        // Map API value to UI value
        // API: 'initiator' = business, 'non-initiator' = customer
        if (bearer === 'initiator') bearer = OPTION_BUSINESS;
        if (bearer === 'non-initiator') bearer = OPTION_CUSTOMER;
        setCurrentBearer(bearer);
        setSelected(bearer);
      } catch (err) {
        logger.error('Failed to fetch charge bearer', { err });
        setFetchError(
          err?.message ||
          t('failedToLoadChargeBearer', {
            ns: 'settings',
            defaultValue: 'Failed to load charge bearer setting.',
          })
        );
        // Sensible default so the UI is still usable
        setCurrentBearer(OPTION_BUSINESS);
        setSelected(OPTION_BUSINESS);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [t]);

  /* ── save ───────────────────────────────────────────────────── */
  const handleSave = async () => {
    if (!selected || selected === currentBearer) { return; }
    setSaving(true);
    try {
      await businessService.updateChargeBearer(selected);
      setCurrentBearer(selected);
      success(
        t('chargeBearerUpdated', {
          ns: 'settings',
          defaultValue: 'Charge bearer updated successfully.',
        })
      );
    } catch (err) {
      logger.error('Failed to update charge bearer', { err });
      showError(
        err?.message ||
        t('failedToUpdateChargeBearer', {
          ns: 'settings',
          defaultValue: 'Failed to update charge bearer setting.',
        })
      );
    } finally {
      setSaving(false);
    }
  };

  const isDirty = selected !== currentBearer;

  /* ── option card ────────────────────────────────────────────── */
  const OptionCard = ({ value, icon, title, description }) => {
    const isActive = selected === value;
    return (
      <button
        type="button"
        onClick={() => setSelected(value)}
        style={{
          display: 'flex',
          alignItems: 'flex-start',
          gap: '16px',
          width: '100%',
          padding: '20px 24px',
          borderRadius: '12px',
          border: `2px solid ${isActive ? 'var(--accent)' : 'var(--border-primary)'}`,
          background: isActive ? 'var(--accent-bg, rgba(59,130,246,0.06))' : 'var(--card)',
          cursor: 'pointer',
          textAlign: 'left',
          transition: 'all 0.2s ease',
          boxShadow: isActive ? '0 0 0 3px rgba(59,130,246,0.15)' : 'none',
        }}
        aria-pressed={isActive}
      >
        {/* icon bubble */}
        <span
          className="material-symbols-outlined"
          style={{
            fontSize: 28,
            color: isActive ? 'var(--accent)' : 'var(--text-muted)',
            background: isActive ? 'rgba(59,130,246,0.12)' : 'var(--bg-tertiary)',
            borderRadius: '10px',
            padding: '8px',
            flexShrink: 0,
            transition: 'all 0.2s ease',
          }}
        >
          {icon}
        </span>

        {/* text */}
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{
            fontSize: '1rem',
            fontWeight: 700,
            color: isActive ? 'var(--accent)' : 'var(--text-primary)',
            marginBottom: '4px',
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
          }}>
            {title}
            {currentBearer === value && (
              <span style={{
                fontSize: '11px',
                fontWeight: 600,
                padding: '2px 8px',
                borderRadius: '20px',
                background: 'var(--success-bg, rgba(16,185,129,0.1))',
                color: 'var(--success, #10b981)',
                border: '1px solid rgba(16,185,129,0.25)',
              }}>
                {t('current', { ns: 'settings', defaultValue: 'Current' })}
              </span>
            )}
          </div>
          <div style={{
            fontSize: '0.875rem',
            color: 'var(--text-secondary)',
            lineHeight: 1.55,
          }}>
            {description}
          </div>
        </div>

        {/* radio dot */}
        <span style={{
          width: 20,
          height: 20,
          borderRadius: '50%',
          border: `2px solid ${isActive ? 'var(--accent)' : 'var(--border-secondary)'}`,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexShrink: 0,
          marginTop: 2,
          transition: 'all 0.2s ease',
        }}>
          {isActive && (
            <span style={{
              width: 10,
              height: 10,
              borderRadius: '50%',
              background: 'var(--accent)',
            }} />
          )}
        </span>
      </button>
    );
  };

  /* ── render ─────────────────────────────────────────────────── */
  return (
    <div className="invoices-card">
      <div className="card-head">
        <h3 style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <span className="material-symbols-outlined" style={{ fontSize: 22, color: 'var(--accent)' }}>
            receipt_long
          </span>
          {t('chargeBearer', { ns: 'settings', defaultValue: 'Charge Bearer' })}
        </h3>
      </div>

      <div style={{ padding: '24px 28px' }}>

        {/* intro */}
        <div style={{
          padding: '16px 20px',
          borderRadius: '10px',
          background: 'var(--bg-tertiary)',
          border: '1px solid var(--border-primary)',
          marginBottom: '28px',
          display: 'flex',
          gap: 12,
          alignItems: 'flex-start',
        }}>
          <span className="material-symbols-outlined" style={{ fontSize: 20, color: 'var(--accent)', marginTop: 1, flexShrink: 0 }}>
            info
          </span>
          <p style={{ margin: 0, fontSize: '0.9rem', color: 'var(--text-secondary)', lineHeight: 1.6 }}>
            {t('chargeBearerDescription', {
              ns: 'settings',
              defaultValue:
                'Choose who bears the transaction processing fee on collections. When set to "Business", the fee is deducted from your settlement. When set to "Customer", the fee is added on top of the amount the customer pays.',
            })}
          </p>
        </div>

        {/* loading / error */}
        {loading ? (
          <div style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '24px 0', color: 'var(--text-muted)' }}>
            <div style={{
              width: 20, height: 20,
              border: '2px solid var(--border-primary)',
              borderTop: '2px solid var(--accent)',
              borderRadius: '50%',
              animation: 'spin 0.8s linear infinite',
            }} />
            {t('loading', { ns: 'common', defaultValue: 'Loading…' })}
          </div>
        ) : fetchError ? (
          <div style={{
            padding: '14px 18px',
            borderRadius: '10px',
            background: 'var(--error-bg, rgba(239,68,68,0.08))',
            border: '1px solid rgba(239,68,68,0.25)',
            color: 'var(--error, #ef4444)',
            fontSize: '0.9rem',
            marginBottom: 24,
            display: 'flex',
            gap: 8,
            alignItems: 'center',
          }}>
            <span className="material-symbols-outlined" style={{ fontSize: 18 }}>error</span>
            {fetchError}
          </div>
        ) : null}

        {/* option cards */}
        {!loading && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 14, marginBottom: 28 }}>
            <OptionCard
              value={OPTION_BUSINESS}
              icon="storefront"
              title={t('chargeBearerBusiness', { ns: 'settings', defaultValue: 'Business (Absorb fee)' })}
              description={t('chargeBearerBusinessDesc', {
                ns: 'settings',
                defaultValue:
                  'Your business absorbs all transaction fees. Customers pay exactly the amount shown — no extra charges added.',
              })}
            />
            <OptionCard
              value={OPTION_CUSTOMER}
              icon="person"
              title={t('chargeBearerCustomer', { ns: 'settings', defaultValue: 'Customer (Pass-through fee)' })}
              description={t('chargeBearerCustomerDesc', {
                ns: 'settings',
                defaultValue:
                  'The transaction fee is passed to the customer and added on top of the collection amount at checkout.',
              })}
            />
          </div>
        )}

        {/* save button */}
        {!loading && (
          <button
            onClick={handleSave}
            disabled={saving || !isDirty}
            style={{
              display: 'inline-flex',
              alignItems: 'center',
              gap: 8,
              padding: '11px 28px',
              borderRadius: '8px',
              border: 'none',
              background: isDirty && !saving ? 'var(--accent)' : 'var(--text-muted)',
              color: 'white',
              fontWeight: 600,
              fontSize: '0.95rem',
              cursor: isDirty && !saving ? 'pointer' : 'not-allowed',
              transition: 'all 0.2s ease',
              opacity: saving ? 0.75 : 1,
            }}
          >
            {saving ? (
              <>
                <div style={{
                  width: 16, height: 16,
                  border: '2px solid rgba(255,255,255,0.35)',
                  borderTop: '2px solid white',
                  borderRadius: '50%',
                  animation: 'spin 0.8s linear infinite',
                }} />
                {t('saving', { ns: 'settings', defaultValue: 'Saving…' })}
              </>
            ) : (
              <>
                <span className="material-symbols-outlined" style={{ fontSize: 18 }}>save</span>
                {t('saveChanges', { ns: 'settings', defaultValue: 'Save Changes' })}
              </>
            )}
          </button>
        )}

        {/* no-change hint */}
        {!loading && !isDirty && currentBearer && (
          <p style={{ marginTop: 12, fontSize: '0.82rem', color: 'var(--text-muted)' }}>
            {t('noChangesToSave', { ns: 'settings', defaultValue: 'No changes to save.' })}
          </p>
        )}
      </div>
    </div>
  );
};

export default ChargeBearer;
