/**
 * Business Payment Methods Settings Page
 * Manages mobile money and bank accounts for business users
 */

import React, { useState } from 'react';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { usePaymentMethods } from '@/features/payment-methods/hooks/usePaymentMethods.js';
import { useSettlementConfig } from '@/features/payment-methods/hooks/useSettlementConfig.js';

// Components
import MobileMoneyAccountForm from '@/features/payment-methods/components/MobileMoneyAccountForm.jsx';
import MobileMoneyAccountList from '@/features/payment-methods/components/MobileMoneyAccountList.jsx';
import BankAccountForm from '@/features/payment-methods/components/BankAccountForm.jsx';
import BankAccountList from '@/features/payment-methods/components/BankAccountList.jsx';
import SettlementConfigSection from '@/features/payment-methods/components/SettlementConfigSection.jsx';
import SettlementWarningBanner from '@/features/payment-methods/components/SettlementWarningBanner.jsx';
import PaymentMethodsTabs from '@/features/payment-methods/components/PaymentMethodsTabs.jsx';

const PaymentMethods = () => {
  const [activeTab, setActiveTab] = useState('settlement-account');
  const [showTypeChoice, setShowTypeChoice] = useState(false);
  const { success, error } = useToast();

  const {
    mobileMoneyAccounts,
    bankAccounts,
    isLoading,
    isAddingMobileMoney,
    isAddingBankAccount,
    editingAccount,
    newMobileMoney,
    newBankAccount,
    setNewMobileMoney,
    setNewBankAccount,
    setIsAddingMobileMoney,
    setIsAddingBankAccount,
    handleAddMobileMoney,
    handleAddBankAccount,
    handleDeleteAccount,
    handleEditMobileMoney,
    handleEditBankAccount,
    handleCancelAddMobileMoney,
    handleCancelAddBankAccount,
  } = usePaymentMethods(error, success, 'business_contact');

  const {
    settlementConfig,
    setSettlementConfig,
    handleSaveSettlementMode,
    handleResetSettlementMode,
  } = useSettlementConfig(error, success);

  const hasAccountLinked = mobileMoneyAccounts.length > 0 || bankAccounts.length > 0;
  const currentAccountType = mobileMoneyAccounts.length > 0 ? 'momo' : (bankAccounts.length > 0 ? 'bank' : null);

  const handleTabSwitch = () => {
    setIsAddingMobileMoney(false);
    setIsAddingBankAccount(false);
    setShowTypeChoice(false);
  };

  const renderAccountTypeChoice = () => (
    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', padding: '20px' }}>
      <button
        onClick={() => {
          setIsAddingMobileMoney(true);
          setShowTypeChoice(false);
        }}
        style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          gap: '16px',
          padding: '32px',
          backgroundColor: 'var(--bg-tertiary)',
          border: '2px solid var(--border-primary)',
          borderRadius: '12px',
          cursor: 'pointer',
          transition: 'all var(--transition-base)',
        }}
        className="choice-card"
      >
        <span className="material-symbols-outlined" style={{ fontSize: '48px', color: 'var(--accent)' }}>
          smartphone
        </span>
        <div style={{ textAlign: 'center' }}>
          <h4 style={{ margin: '0 0 8px 0', color: 'var(--text-primary)' }}>Mobile Money</h4>
          <p style={{ margin: 0, fontSize: '13px', color: 'var(--text-muted)' }}>Link your MTN, Telecel or AirtelTigo wallet</p>
        </div>
      </button>

      <button
        onClick={() => {
          setIsAddingBankAccount(true);
          setShowTypeChoice(false);
        }}
        style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          gap: '16px',
          padding: '32px',
          backgroundColor: 'var(--bg-tertiary)',
          border: '2px solid var(--border-primary)',
          borderRadius: '12px',
          cursor: 'pointer',
          transition: 'all var(--transition-base)',
        }}
        className="choice-card"
      >
        <span className="material-symbols-outlined" style={{ fontSize: '48px', color: 'var(--accent)' }}>
          account_balance
        </span>
        <div style={{ textAlign: 'center' }}>
          <h4 style={{ margin: '0 0 8px 0', color: 'var(--text-primary)' }}>Bank Account</h4>
          <p style={{ margin: 0, fontSize: '13px', color: 'var(--text-muted)' }}>Link your corporate bank account</p>
        </div>
      </button>
    </div>
  );

  return (
    <div className="invoices-card">
      <div className="card-head">
        <h3>Settlement Methods</h3>
        <p style={{ color: 'var(--text-muted)', margin: 0 }}>
          Manage your mobile money and bank accounts
        </p>
      </div>

      <SettlementWarningBanner />

      <div style={{ padding: '20px' }}>
        <PaymentMethodsTabs
          activeTab={activeTab}
          onTabChange={setActiveTab}
          onTabSwitch={handleTabSwitch}
        />

        {/* Settlement Account Tab */}
        {activeTab === 'settlement-account' && (
          <>
            {/* 1. Account Selection View (When none linked or "adding") */}
            {(!hasAccountLinked || showTypeChoice) && !isAddingMobileMoney && !isAddingBankAccount && (
              renderAccountTypeChoice()
            )}

            {/* 2. MoMo Form */}
            {isAddingMobileMoney && (
              <MobileMoneyAccountForm
                formData={newMobileMoney}
                onChange={setNewMobileMoney}
                onSubmit={handleAddMobileMoney}
                onCancel={() => {
                  handleCancelAddMobileMoney();
                  if (!hasAccountLinked) {
                    setShowTypeChoice(false);
                  }
                }}
                isEditing={editingAccount === 'momo'}
                isLoading={isLoading}
              />
            )}

            {/* 3. Bank Form */}
            {isAddingBankAccount && (
              <BankAccountForm
                formData={newBankAccount}
                onChange={setNewBankAccount}
                onSubmit={handleAddBankAccount}
                onCancel={() => {
                  handleCancelAddBankAccount();
                  if (!hasAccountLinked) {
                    setShowTypeChoice(false);
                  }
                }}
                isEditing={editingAccount === 'bank'}
                isLoading={isLoading}
              />
            )}

            {/* 4. Linked Account View */}
            {hasAccountLinked && !isAddingMobileMoney && !isAddingBankAccount && !showTypeChoice && (
              <div style={{ padding: '0 10px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                  <h4 style={{ margin: 0, color: 'var(--text-primary)' }}>Linked Account</h4>
                  <button
                    onClick={() => setShowTypeChoice(true)}
                    style={{
                      padding: '8px 16px',
                      backgroundColor: 'transparent',
                      color: 'var(--accent)',
                      border: '1px solid var(--accent)',
                      borderRadius: '6px',
                      cursor: 'pointer',
                      fontSize: '13px',
                      fontWeight: '600'
                    }}
                  >
                    Change Account Type
                  </button>
                </div>

                {currentAccountType === 'momo' ? (
                  <MobileMoneyAccountList
                    accounts={mobileMoneyAccounts}
                    onEdit={handleEditMobileMoney}
                    onDelete={(id) => handleDeleteAccount(id, 'momo')}
                    maxAccounts={1}
                  />
                ) : (
                  <BankAccountList
                    accounts={bankAccounts}
                    onEdit={handleEditBankAccount}
                    onDelete={(id) => handleDeleteAccount(id, 'bank')}
                    maxAccounts={1}
                  />
                )}
              </div>
            )}
          </>
        )}

        {/* Settlement Configuration Tab */}
        {activeTab === 'settlement-config' && (
          <SettlementConfigSection
            settlementConfig={settlementConfig}
            setSettlementConfig={setSettlementConfig}
            mobileMoneyAccounts={mobileMoneyAccounts}
            bankAccounts={bankAccounts}
            onSave={handleSaveSettlementMode}
            onReset={handleResetSettlementMode}
            isLoading={isLoading}
          />
        )}
      </div>
    </div>
  );
};

export default PaymentMethods;
