/**
 * Custom Hook for Business Information Management
 * 
 * Handles loading, editing, and updating business information including
 * trading name, description, staff size, revenue, TIN, and registration type.
 */

import { useState, useEffect, useCallback } from 'react';
import { businessService, profileService } from '@/features/settings/services';
import { tokenService } from '@/features/auth/services';
import { logger } from '@/shared/utils/logger.js';

/**
 * Parse business phone number into country code and phone number
 * @param {string} fullPhone - Full phone number (e.g., '233201234567')
 * @returns {object} - { businessPhoneCountryCode, businessPhone }
 */
const parseBusinessPhone = (fullPhone) => {
  if (!fullPhone || fullPhone.trim() === '') {
    return {
      businessPhoneCountryCode: '233', // Default to Ghana
      businessPhone: ''
    };
  }

  // Remove any '+' or whitespace
  const cleaned = fullPhone.replace(/[\s+\-()]/g, '');

  // Common country codes (sorted by length, longest first for proper matching)
  const countryCodePatterns = [
    /^(1242|1246|1264|1268|1284|1340|1345|1441|1473|1649|1664|1670|1671|1684|1721|1758|1767|1784|1787|1809|1829|1849|1868|1869|1876)/, // 4-digit codes
    /^(233|234|235|236|237|238|239|240|241|242|243|244|245|246|247|248|249|250|251|252|253|254|255|256|257|258|259|260|261|262|263|264|265|266|267|268|269|290|291|297|298|299|350|351|352|353|354|355|356|357|358|359|370|371|372|373|374|375|376|377|378|379|380|381|382|385|386|387|389|420|421|423|590|591|592|593|594|595|596|597|598|599|670|672|673|674|675|676|677|678|679|680|681|682|683|684|685|686|687|688|689|690|691|692|850|852|853|855|856|870|880|886|960|961|962|963|964|965|966|967|968|970|971|972|973|974|975|976|977|992|993|994|995|996|998)/, // 3-digit codes
    /^(20|27|30|31|32|33|34|36|39|40|41|43|44|45|46|47|48|49|51|52|53|54|55|56|57|58|60|61|62|63|64|65|66|81|82|84|86|90|91|92|93|94|95|98)/, // 2-digit codes
    /^(1|7)/ // 1-digit codes (US/Canada and Russia/Kazakhstan)
  ];

  for (const pattern of countryCodePatterns) {
    const match = cleaned.match(pattern);
    if (match) {
      const countryCode = match[1];
      const phoneNumber = cleaned.substring(countryCode.length);
      return {
        businessPhoneCountryCode: countryCode,
        businessPhone: phoneNumber
      };
    }
  }

  // If no country code pattern matches, assume Ghana (+233)
  if (cleaned.startsWith('0')) {
    // Remove leading 0 for Ghana numbers
    return {
      businessPhoneCountryCode: '233',
      businessPhone: cleaned.substring(1)
    };
  }

  // Default: treat entire number as phone number with Ghana code
  return {
    businessPhoneCountryCode: '233',
    businessPhone: cleaned
  };
};
import { useMutation, useQuery } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';

export const useBusinessInfo = () => {
  const [formData, setFormData] = useState({
    tradingName: '',
    description: '',
    staffSize: '',
    expectedMonthlyRevenue: '',
    tinNumber: '',
    registrationType: '',
    // Contact Information
    businessEmail: '',
    supportEmail: '',
    disputesEmail: '',
    businessPhone: '',
    businessPhoneCountryCode: '233', // Default to Ghana
    websiteUrl: '',
    // Address Information
    registeredOffice: '',
    operatingAddress: '',
    gpsAddress: '',
    // Business Details
    industry: '',
    category: '',
    registrationNumber: '',
    dateOfIncorporation: ''
  });

  const [isEditMode, setIsEditMode] = useState(false);
  const [originalFormData, setOriginalFormData] = useState({});
  const [businessType, setBusinessType] = useState(null);
  const [businessId, setBusinessId] = useState(null);

  /**
   * Get business ID from localStorage or profile
   */
  const getBusinessId = useCallback(async () => {
    try {
      const userData = JSON.parse(localStorage.getItem('userData') || '{}');
      const storedBusinessId = localStorage.getItem('businessId');

      if (storedBusinessId) {
        logger.debug('Business ID found in localStorage', { businessId: storedBusinessId });
        return storedBusinessId;
      }

      if (userData?.businesses?.[0]?.id || userData?.business?.id || userData?.business_id || userData?.businessId) {
        const businessId = userData.businesses?.[0]?.id || userData.business?.id || userData.business_id || userData.businessId;
        logger.debug('Business ID found in userData', { businessId });
        localStorage.setItem('businessId', businessId);
        return businessId;
      }

      // Fallback: try to fetch fresh profile data
      logger.debug('Business ID not found, fetching fresh profile data');
      const profileData = await profileService.getUserProfile();
      logger.debug('Fresh profile data received', { profileData });

      if (profileData?.businesses?.[0]?.id || profileData?.business?.id || profileData?.business_id || profileData?.businessId) {
        const freshBusinessId = profileData.businesses?.[0]?.id || profileData.business?.id || profileData.business_id || profileData.businessId;
        logger.debug('Found business ID in fresh profile data', { businessId: freshBusinessId });

        // Update localStorage with fresh data
        const currentUserData = JSON.parse(localStorage.getItem('userData') || '{}');
        // Preserve the original login user ID - don't let profile data overwrite it
        const preservedId = currentUserData.id;
        const { id: profileId, ...profileDataWithoutId } = profileData;
        const updatedUserData = {
          ...currentUserData,
          ...profileDataWithoutId,
          id: preservedId // Always preserve the login user ID
        };
        localStorage.setItem('userData', JSON.stringify(updatedUserData));
        localStorage.setItem('businessId', freshBusinessId);

        return freshBusinessId;
      }

      logger.warn('No business ID found', { userType: profileData?.usertype || userData?.usertype });
      return null;
    } catch (error) {
      logger.error('Error getting business ID', { error });
      return null;
    }
  }, []);

  // Get business ID on mount
  useEffect(() => {
    getBusinessId().then(id => {
      if (id) {
        logger.debug('Business ID set in useBusinessInfo', { businessId: id });
        setBusinessId(id);
      } else {
        logger.warn('No business ID found in useBusinessInfo');
      }
    });
  }, [getBusinessId]);

  // Use React Query to load business data with automatic caching and refetching
  const { data: businessData, isLoading, error: loadingError } = useQuery({
    queryKey: queryKeys.settings.business(),
    endpoint: `/auth/business/${businessId}/business-info`,
    enabled: !!businessId,
    staleTime: 2 * 60 * 1000, // 2 minutes
    refetchOnWindowFocus: false, // Reduced from true to prevent excessive refetches
    select: (response) => {
      logger.debug('Business data response received', { response });
      const businessInfo = response?.data || response || {};
      logger.debug('Parsed business info', { businessInfo });
      return {
        formData: {
          tradingName: businessInfo.trading_name || '',
          description: businessInfo.description || '',
          staffSize: businessInfo.staff_size || '',
          expectedMonthlyRevenue: businessInfo.expected_monthly_revenue || '',
          tinNumber: businessInfo.tin_number || '',
          registrationType: (businessInfo.registration_type || '').toLowerCase().replace(/ /g, '_'),
          // Contact Information
          businessEmail: businessInfo.business_email || '',
          supportEmail: businessInfo.support_email || '',
          disputesEmail: businessInfo.disputes_email || '',
          // Parse business phone into country code and number
          ...parseBusinessPhone(businessInfo.business_phone),
          websiteUrl: businessInfo.website_url || '',
          // Address Information
          registeredOffice: businessInfo.registered_office || '',
          operatingAddress: businessInfo.operating_address || '',
          gpsAddress: businessInfo.gps_address || '',
          // Business Details
          industry: businessInfo.industry || '',
          category: businessInfo.category || '',
          registrationNumber: businessInfo.registration_number || '',
          // Convert ISO date string to YYYY-MM-DD format for HTML date input
          dateOfIncorporation: businessInfo.date_of_incorporation 
            ? (() => {
                try {
                  return new Date(businessInfo.date_of_incorporation).toISOString().split('T')[0];
                } catch (e) {
                  logger.warn('Failed to convert date_of_incorporation to YYYY-MM-DD format', { date_of_incorporation: businessInfo.date_of_incorporation, error: e });
                  return '';
                }
              })()
            : ''
        },
        businessType: businessInfo.business_type || 'Starter'
      };
    },
    onError: (error) => {
      logger.error('Error loading business data', { error });
    },
  });

  // Update form data when business data changes
  useEffect(() => {
    if (businessData) {
      setFormData(businessData.formData);
      setOriginalFormData(businessData.formData);
      setBusinessType(businessData.businessType);
    }
  }, [businessData]);

  // Use React Query mutation for updating business information
  const updateBusinessInfoMutation = useMutation({
    mutationFn: async (updateData) => {
      if (!businessId) {
        throw new Error('Business ID not found');
      }
      return await businessService.updateBusinessInfo(businessId, updateData);
    },
    invalidateQueries: [
      queryKeys.settings.business(),
      queryKeys.settings.all(),
    ],
    onSuccess: () => {
      logger.info('Business information updated successfully');
      setOriginalFormData(formData);
      setIsEditMode(false);
    },
    onError: (error) => {
      logger.error('Error updating business information', { error });
      throw error;
    },
  });

  const updateBusinessInfo = useCallback(async () => {
    logger.debug('Updating business information', { formData });
    
    // Format phone number: remove leading zeros and combine with country code
    let formattedPhone = '';
    if (formData.businessPhoneCountryCode && formData.businessPhone) {
      // Remove leading zeros from phone number
      let cleanedPhone = formData.businessPhone.replace(/^0+/, '');
      // Remove any non-digit characters
      cleanedPhone = cleanedPhone.replace(/[^\d]/g, '');
      // Get country code without '+'
      const countryCode = formData.businessPhoneCountryCode.replace(/^\+/, '').replace(/[^\d]/g, '');
      // Combine: country code + cleaned phone (no leading zero)
      formattedPhone = `${countryCode}${cleanedPhone}`;
    }
    
    await updateBusinessInfoMutation.mutateAsync({
      tradingName: formData.tradingName,
      description: formData.description,
      staffSize: formData.staffSize,
      expectedMonthlyRevenue: formData.expectedMonthlyRevenue,
      tinNumber: formData.tinNumber,
      registrationType: formData.registrationType,
      // Contact Information
      businessEmail: formData.businessEmail,
      supportEmail: formData.supportEmail,
      disputesEmail: formData.disputesEmail,
      // Send formatted phone: country code + number (no leading zero)
      businessPhone: formattedPhone,
      websiteUrl: formData.websiteUrl,
      // Address Information
      registeredOffice: formData.registeredOffice,
      operatingAddress: formData.operatingAddress,
      gpsAddress: formData.gpsAddress,
      // Business Details
      industry: formData.industry,
      category: formData.category,
      registrationNumber: formData.registrationNumber,
      dateOfIncorporation: formData.dateOfIncorporation
    });
    return true;
  }, [formData, updateBusinessInfoMutation]);

  /**
   * Enter edit mode
   */
  const enterEditMode = useCallback(() => {
    setIsEditMode(true);
  }, []);

  /**
   * Cancel edit mode
   */
  const cancelEdit = useCallback(() => {
    setFormData(originalFormData);
    setIsEditMode(false);
  }, [originalFormData]);

  /**
   * Check if business profile is complete (email and phone set)
   */
  const isProfileComplete = useCallback(() => {
    const hasEmail = formData.businessEmail && formData.businessEmail.trim() !== '';
    const hasPhone = formData.businessPhone && formData.businessPhone.trim() !== '';
    const hasCountryCode = formData.businessPhoneCountryCode && formData.businessPhoneCountryCode.trim() !== '';

    // Check if both country code and phone number are provided
    const isPhoneComplete = hasCountryCode && hasPhone;

    // Validate phone number format (digits only, reasonable length)
    const isPhoneValid = isPhoneComplete && /^\d{7,15}$/.test(formData.businessPhone);

    return hasEmail && isPhoneValid;
  }, [formData.businessEmail, formData.businessPhone, formData.businessPhoneCountryCode]);

  return {
    formData,
    setFormData,
    isLoading: isLoading || updateBusinessInfoMutation.isPending,
    loadingError: loadingError?.message || null,
    isEditMode,
    businessType,
    enterEditMode,
    cancelEdit,
    updateBusinessInfo,
    isProfileComplete,
    reload: () => { } // React Query handles refetching automatically
  };
};

