/**
 * Team Member List Component
 * 
 * Displays list of team members for a specific team. Handles member removal
 * with confirmation dialogs and refreshes the list after operations.
 */

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { teamService } from '@/features/settings/services';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useQuery, useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import logger from '@/shared/utils/logger.js';

const TeamMemberList = ({ businessId, teamId, onMemberRemoved }) => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const [memberToRemove, setMemberToRemove] = useState(null);
  const [showConfirmDialog, setShowConfirmDialog] = useState(false);

  // Use React Query to fetch team members
  const { data: members = [], isLoading, refetch } = useQuery({
    queryKey: ['team', 'members', businessId, teamId],
    endpoint: `/api/team/${teamId}/members`,
    enabled: !!(teamId && businessId),
    staleTime: 3 * 60 * 1000, // 3 minutes - team members change occasionally
    cacheTime: 10 * 60 * 1000, // 10 minutes
    refetchOnWindowFocus: false, // Reduced from true to prevent excessive refetches
    select: (response) => {
      logger.debug('TeamMemberList - Raw API response', { response });

      // Extract data from API response (response structure: { code: "00", data: [...], message: "..." })
      const teamMembers = response?.data || (Array.isArray(response) ? response : []);

      logger.debug('TeamMemberList - Extracted teamMembers', { 
        teamMembers, 
        isArray: Array.isArray(teamMembers),
        length: teamMembers?.length 
      });

      // Transform the API response to extract user data from nested 'users' object
      if (Array.isArray(teamMembers) && teamMembers.length > 0) {
        const transformed = teamMembers.map(member => {
          logger.debug('TeamMemberList - Processing member', { member });
          return {
            id: member.id || member.user_id,
            user_id: member.user_id,
            team_id: member.team_id,
            created_at: member.created_at,
            name: member.users?.full_name || member.name || member.full_name || 'Unknown',
            email: member.users?.email || member.email || '',
            phone: member.users?.phone || member.phone || member.phone_number || '',
            phone_number: member.users?.phone || member.phone || member.phone_number || '',
            status: member.users?.status || member.status || 'active',
            role: member.role || 'member',
            users: member.users // Keep the full users object for reference
          };
        });
        logger.debug('TeamMemberList - Transformed members', { transformed });
        return transformed;
      }
      logger.warn('TeamMemberList - No members found or empty array');
      return [];
    },
    onError: (error) => {
      logger.error('Failed to load team members', { error });
      showError(t('failedToLoadTeamMembers', { ns: 'settings' }));
    },
  });

  // Remove team member mutation
  const removeTeamMemberMutation = useMutation({
    mutationFn: async ({ teamId, memberId }) => {
      return await teamService.removeTeamMember(teamId, memberId);
    },
    invalidateQueries: [
      ['team', 'members', businessId, teamId],
      queryKeys.settings.team(),
      ['team', 'details'],
    ],
    onSuccess: () => {
      success(t('teamMemberRemoved', { ns: 'settings', defaultValue: 'Team member removed successfully' }));
      setShowConfirmDialog(false);
      setMemberToRemove(null);
      refetch();
      if (onMemberRemoved) {
        onMemberRemoved();
      }
    },
    onError: (error) => {
      showError(error.message || t('failedToRemoveTeamMember', { ns: 'settings', defaultValue: 'Failed to remove team member' }));
      setShowConfirmDialog(false);
      setMemberToRemove(null);
    },
  });

  const handleRemoveClick = (member) => {
    setMemberToRemove(member);
    setShowConfirmDialog(true);
  };

  const handleConfirmRemove = () => {
    if (memberToRemove) {
      removeTeamMemberMutation.mutate({
        teamId: teamId,
        memberId: memberToRemove.user_id  // Use user_id, not the team_members table id
      });
    }
  };

  const handleCancelRemove = () => {
    setShowConfirmDialog(false);
    setMemberToRemove(null);
  };

  // Helper function to check if a value appears to be encrypted/hashed
  const isEncrypted = (value) => {
    if (!value || typeof value !== 'string') {return false;}
    // Check if it looks like base64 encoded data (common encryption format)
    // Base64 strings are typically long and contain +, /, = characters
    const base64Pattern = /^[A-Za-z0-9+/=]{20,}$/;
    return base64Pattern.test(value.replace(/\s/g, ''));
  };

  const getRoleBadgeColor = (role) => {
    switch (role) {
      case 'admin':
        return { bg: 'var(--warning-bg)', color: 'var(--warning)', border: 'var(--warning)' };
      case 'viewer':
        return { bg: 'var(--info-bg)', color: 'var(--info)', border: 'var(--info)' };
      default:
        return { bg: 'var(--bg-secondary)', color: 'var(--text-secondary)', border: 'var(--border-secondary)' };
    }
  };

  const getRoleLabel = (role) => {
    switch (role) {
      case 'admin':
        return t('admin', { ns: 'settings' });
      case 'viewer':
        return t('viewer', { ns: 'settings' });
      default:
        return t('member', { ns: 'settings' });
    }
  };

  const getStatusBadgeColor = (status) => {
    switch (status) {
      case 'active':
        return { bg: 'var(--success-bg)', color: 'var(--success)', border: 'var(--success)' };
      case 'inactive':
        return { bg: 'var(--error-bg)', color: 'var(--error)', border: 'var(--error)' };
      default:
        return { bg: 'var(--bg-secondary)', color: 'var(--text-secondary)', border: 'var(--border-secondary)' };
    }
  };

  const getStatusLabel = (status) => {
    switch (status) {
      case 'active':
        return t('active', { ns: 'settings' });
      case 'inactive':
        return t('inactive', { ns: 'settings' });
      default:
        return status;
    }
  };

  if (isLoading) {
    return (
      <div style={{
        padding: '24px',
        textAlign: 'center',
        border: '1px solid var(--border-primary)',
        borderRadius: '8px',
        backgroundColor: 'var(--bg-tertiary)'
      }}>
        <div style={{
          width: '24px',
          height: '24px',
          border: '3px solid var(--border-secondary)',
          borderTop: '3px solid var(--accent)',
          borderRadius: '50%',
          animation: 'spin 1s linear infinite',
          margin: '0 auto 12px'
        }} />
        <p style={{ color: 'var(--text-muted)', margin: 0 }}>{t('loadingTeamMembers', { ns: 'settings' })}</p>
      </div>
    );
  }

  if (members.length === 0) {
    return (
      <div style={{
        padding: '32px 24px',
        textAlign: 'center',
        border: '1px solid var(--border-primary)',
        borderRadius: '8px',
        backgroundColor: 'var(--bg-tertiary)'
      }}>
        <div style={{
          width: '64px',
          height: '64px',
          borderRadius: '50%',
          background: 'linear-gradient(135deg, var(--accent) 0%, var(--accent-hover) 100%)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          margin: '0 auto 16px',
          boxShadow: 'var(--shadow-md)'
        }}>
          <span className="material-symbols-outlined" style={{ fontSize: '32px', color: 'white' }}>
            person_add
          </span>
        </div>
        <h3 style={{
          margin: '0 0 8px 0',
          fontSize: '16px',
          fontWeight: '600',
          color: 'var(--text-primary)'
        }}>
          {t('noTeamMembersYet', { ns: 'settings' })}
        </h3>
        <p style={{
          margin: '0 0 16px 0',
          fontSize: '14px',
          color: 'var(--text-muted)'
        }}>
          {t('addTeamMembersToGetStarted', { ns: 'settings' })}
        </p>
      </div>
    );
  }

  return (
    <>
      <div style={{
        border: '1px solid var(--border-primary)',
        borderRadius: '8px',
        overflow: 'hidden',
        backgroundColor: 'var(--card)'
      }}>
        <div style={{
          padding: '16px 20px',
          borderBottom: '1px solid var(--border-primary)',
          backgroundColor: 'var(--bg-tertiary)'
        }}>
          <h4 style={{
            margin: 0,
            fontSize: '14px',
            fontWeight: '600',
            color: 'var(--text-primary)'
          }}>
            {t('teamMembers', { ns: 'settings' })} ({members.length})
          </h4>
        </div>

        <div style={{ maxHeight: '400px', overflow: 'auto' }}>
          {members.map((member) => {
            return (
              <div
                key={member.id}
                style={{
                  padding: '16px 20px',
                  borderBottom: '1px solid var(--border-primary)',
                  backgroundColor: 'var(--card)',
                  transition: 'background-color 0.2s ease'
                }}
                onMouseEnter={(e) => e.currentTarget.style.backgroundColor = 'var(--bg-hover)'}
                onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'var(--card)'}
              >
                <div style={{
                  display: 'flex',
                  alignItems: 'flex-start',
                  justifyContent: 'space-between',
                  gap: '16px'
                }}>
                  {/* Member Info */}
                  <div style={{
                    display: 'flex',
                    alignItems: 'flex-start',
                    gap: '12px',
                    flex: 1
                  }}>
                    <div style={{
                      width: '40px',
                      height: '40px',
                      borderRadius: '50%',
                      background: 'linear-gradient(135deg, var(--accent) 0%, var(--accent-hover) 100%)',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      fontSize: '16px',
                      fontWeight: '600',
                      color: 'white',
                      boxShadow: 'var(--shadow-sm)',
                      flexShrink: 0
                    }}>
                      {member.name ? member.name.charAt(0).toUpperCase() : (
                        <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>person</span>
                      )}
                    </div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <h5 style={{
                        margin: '0 0 4px 0',
                        fontSize: '15px',
                        fontWeight: '600',
                        color: 'var(--text-primary)'
                      }}>
                        {member.name}
                      </h5>
                      <div style={{
                        display: 'flex',
                        flexDirection: 'column',
                        gap: '2px'
                      }}>
                        {member.email && !isEncrypted(member.email) && (
                          <p style={{
                            margin: 0,
                            fontSize: '13px',
                            color: 'var(--text-muted)',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '6px',
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                            whiteSpace: 'nowrap'
                          }}>
                            <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>email</span>
                            {member.email}
                          </p>
                        )}
                        {member.phone && !isEncrypted(member.phone) && (
                          <p style={{
                            margin: 0,
                            fontSize: '13px',
                            color: 'var(--text-muted)',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '6px'
                          }}>
                            <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>phone</span>
                            {member.phone}
                          </p>
                        )}
                      </div>
                    </div>
                  </div>

                  {/* Actions */}
                  <div style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: '8px'
                  }}>
                    <button
                      onClick={() => handleRemoveClick(member)}
                      disabled={removeTeamMemberMutation.isPending}
                      style={{
                        padding: '6px 12px',
                        backgroundColor: 'var(--error-bg)',
                        color: 'var(--error)',
                        border: '1px solid var(--error)',
                        borderRadius: '6px',
                        fontSize: '12px',
                        fontWeight: '500',
                        cursor: removeTeamMemberMutation.isPending ? 'not-allowed' : 'pointer',
                        display: 'inline-flex',
                        alignItems: 'center',
                        gap: '4px',
                        transition: 'all var(--transition-base)',
                        opacity: removeTeamMemberMutation.isPending ? 0.6 : 1
                      }}
                      onMouseEnter={(e) => {
                        if (!removeTeamMemberMutation.isPending) {
                          e.target.style.backgroundColor = 'var(--error)';
                          e.target.style.color = 'white';
                        }
                      }}
                      onMouseLeave={(e) => {
                        if (!removeTeamMemberMutation.isPending) {
                          e.target.style.backgroundColor = 'var(--error-bg)';
                          e.target.style.color = 'var(--error)';
                        }
                      }}
                    >
                      <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>delete</span>
                      {t('remove', { ns: 'settings', defaultValue: 'Remove' })}
                    </button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Confirmation Dialog */}
      {showConfirmDialog && memberToRemove && createPortal(
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(0, 0, 0, 0.5)',
          backdropFilter: 'blur(4px)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 99999,
          padding: '20px'
        }}>
          <div style={{
            backgroundColor: 'var(--card)',
            borderRadius: '12px',
            width: '100%',
            maxWidth: '450px',
            boxShadow: 'var(--shadow-xl)',
            overflow: 'hidden'
          }}>
            {/* Header */}
            <div style={{
              padding: '24px',
              borderBottom: '1px solid var(--border-primary)',
              backgroundColor: 'var(--error-bg)'
            }}>
              <div style={{
                display: 'flex',
                alignItems: 'center',
                gap: '12px'
              }}>
                <span className="material-symbols-outlined" style={{ fontSize: '28px', color: 'var(--error)' }}>
                  warning
                </span>
                <div>
                  <h2 style={{
                    margin: 0,
                    fontSize: '18px',
                    fontWeight: '700',
                    color: 'var(--text-primary)'
                  }}>
                    {t('confirmRemoveMember', { ns: 'settings', defaultValue: 'Remove Team Member?' })}
                  </h2>
                  <p style={{
                    margin: '4px 0 0 0',
                    fontSize: '14px',
                    color: 'var(--text-muted)'
                  }}>
                    {t('thisActionCannotBeUndone', { ns: 'settings', defaultValue: 'This action cannot be undone' })}
                  </p>
                </div>
              </div>
            </div>

            {/* Body */}
            <div style={{ padding: '24px' }}>
              <p style={{
                margin: '0 0 16px 0',
                fontSize: '14px',
                color: 'var(--text-primary)',
                lineHeight: '1.5'
              }}>
                {t('confirmRemoveMemberMessage', {
                  ns: 'settings',
                  defaultValue: 'Are you sure you want to remove this team member?'
                })}
              </p>
              <div style={{
                padding: '12px',
                backgroundColor: 'var(--bg-tertiary)',
                borderRadius: '8px',
                border: '1px solid var(--border-primary)'
              }}>
                <p style={{
                  margin: '0 0 4px 0',
                  fontSize: '14px',
                  fontWeight: '600',
                  color: 'var(--text-primary)'
                }}>
                  {memberToRemove.name}
                </p>
                {memberToRemove.email && !isEncrypted(memberToRemove.email) && (
                  <p style={{
                    margin: '0 0 2px 0',
                    fontSize: '13px',
                    color: 'var(--text-muted)'
                  }}>
                    {memberToRemove.email}
                  </p>
                )}
                {memberToRemove.phone && !isEncrypted(memberToRemove.phone) && (
                  <p style={{
                    margin: 0,
                    fontSize: '13px',
                    color: 'var(--text-muted)'
                  }}>
                    {memberToRemove.phone}
                  </p>
                )}
              </div>
            </div>

            {/* Footer */}
            <div style={{
              padding: '20px 24px',
              borderTop: '1px solid var(--border-primary)',
              backgroundColor: 'var(--bg-tertiary)',
              display: 'flex',
              justifyContent: 'flex-end',
              gap: '12px'
            }}>
              <button
                onClick={handleCancelRemove}
                disabled={removeTeamMemberMutation.isPending}
                style={{
                  padding: '10px 20px',
                  backgroundColor: 'var(--bg-input)',
                  border: '1px solid var(--border-secondary)',
                  borderRadius: '8px',
                  fontSize: '14px',
                  fontWeight: '500',
                  color: 'var(--text-secondary)',
                  cursor: removeTeamMemberMutation.isPending ? 'not-allowed' : 'pointer',
                  transition: 'all 0.2s ease',
                  opacity: removeTeamMemberMutation.isPending ? 0.6 : 1
                }}
                onMouseEnter={(e) => {
                  if (!removeTeamMemberMutation.isPending) {
                    e.target.style.backgroundColor = 'var(--bg-hover)';
                    e.target.style.borderColor = 'var(--border-primary)';
                  }
                }}
                onMouseLeave={(e) => {
                  if (!removeTeamMemberMutation.isPending) {
                    e.target.style.backgroundColor = 'var(--bg-input)';
                    e.target.style.borderColor = 'var(--border-secondary)';
                  }
                }}
              >
                {t('cancel', { ns: 'settings' })}
              </button>
              <button
                onClick={handleConfirmRemove}
                disabled={removeTeamMemberMutation.isPending}
                style={{
                  padding: '10px 20px',
                  backgroundColor: removeTeamMemberMutation.isPending ? 'var(--text-muted)' : 'var(--error)',
                  border: 'none',
                  borderRadius: '8px',
                  fontSize: '14px',
                  fontWeight: '500',
                  color: 'white',
                  cursor: removeTeamMemberMutation.isPending ? 'not-allowed' : 'pointer',
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '8px',
                  transition: 'background-color 0.2s ease'
                }}
                onMouseEnter={(e) => {
                  if (!removeTeamMemberMutation.isPending) {e.target.style.backgroundColor = 'var(--error-hover)';}
                }}
                onMouseLeave={(e) => {
                  if (!removeTeamMemberMutation.isPending) {e.target.style.backgroundColor = 'var(--error)';}
                }}
              >
                {removeTeamMemberMutation.isPending ? (
                  <>
                    <div style={{
                      width: '14px',
                      height: '14px',
                      border: '2px solid transparent',
                      borderTop: '2px solid currentColor',
                      borderRadius: '50%',
                      animation: 'spin 1s linear infinite'
                    }} />
                    {t('removing', { ns: 'settings', defaultValue: 'Removing...' })}
                  </>
                ) : (
                  <>
                    <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>delete</span>
                    {t('removeMember', { ns: 'settings', defaultValue: 'Remove Member' })}
                  </>
                )}
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}
    </>
  );
};

export default TeamMemberList;
