/**
 * Add Team Member Modal Component
 * 
 * Modal dialog for adding new members to a team. Collects member information
 * including name, email, phone number, and role. Validates input and handles
 * team member creation via team service.
 */

import React, { useState, useMemo, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { teamService } from '@/features/settings/services';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import { FlagIcon, LoadingSpinner } from '@/shared/components';
import { createTeamMemberSchema } from '@/shared/utils/validation/settingsSchemas.js';
import { mapFieldErrors } from '@/shared/utils/validation/helpers.js';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import logger from '@/shared/utils/logger.js';

const AddTeamMemberModal = ({ isOpen, onClose, businessId, teamId, onMemberAdded }) => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phoneCountryCode: '+233',
    phoneNumber: '',
    role: 'member'
  });
  const [formErrors, setFormErrors] = useState({});

  // Use React Query mutation for adding team member
  const addTeamMemberMutation = useMutation({
    mutationFn: async (memberData) => {
      return await teamService.addTeamMember(teamId, memberData);
    },
    invalidateQueries: [
      queryKeys.settings.team(),
      ['team', 'details'],
    ],
    onSuccess: (addedMember) => {
      success(t('teamMemberAdded', { ns: 'settings' }));
      // Reset form
      setFormData({
        name: '',
        email: '',
        phoneCountryCode: '+233',
        phoneNumber: '',
        role: 'member'
      });
      onMemberAdded(addedMember);
      onClose();
    },
    onError: (error) => {
      showError(error.message || t('failedToAddTeamMember', { ns: 'settings' }));
    },
  });

  const availableRoles = useMemo(() => [
    { value: 'member', label: t('member', { ns: 'settings' }), description: t('memberDescription', { ns: 'settings' }) }
  ], [t]);

  const selectedPhoneCountry = countries.find(c => c.dialCode === formData.phoneCountryCode) || countries.find(c => c.code === 'GH');

  const clearFieldError = (name) => {
    if (formErrors[name]) {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next[name];
        if (Object.keys(next).length === 1 && next._form) {
          delete next._form;
        }
        return next;
      });
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    clearFieldError(name);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    logger.debug('AddTeamMemberModal: businessId', { businessId });

    const schema = createTeamMemberSchema(t);
    const validation = schema.safeParse(formData);

    if (!validation.success) {
      const errors = mapFieldErrors(validation.error);
      setFormErrors(errors);
      const message = Object.values(errors)[0] || t('pleaseFillInAllFields', { ns: 'settings' });
      showError(message);
      return;
    }
    const validated = validation.data;

    // Clean phone number (remove plus and leading zero) and format with country code
    const cleanedPhone = cleanNumberForBackend(validated.phoneNumber.trim());
    const countryCode = cleanNumberForBackend(validated.phoneCountryCode);
    // Combine country code with cleaned phone number
    const formattedPhone = countryCode + cleanedPhone;
    
    const memberData = {
      name: validated.name.trim(),
      email: validated.email.trim().toLowerCase(),
      phone: formattedPhone,
      phoneNumber: formattedPhone, // Keep for backward compatibility
      full_name: validated.name.trim(), // API expects full_name
      role: validated.role,
      status: 'active'
    };

    addTeamMemberMutation.mutate(memberData);
  };

  const handlePhoneChange = (e) => {
    const value = e.target.value;
    // Allow only numbers, +, and spaces
    let cleanValue = value.replace(/[^0-9+\s]/g, '');

    // Automatically remove leading zero if present
    if (cleanValue.startsWith('0')) {
      cleanValue = cleanValue.substring(1);
    }

    setFormData(prev => ({
      ...prev,
      phoneNumber: cleanValue
    }));
    clearFieldError('phoneNumber');
    clearFieldError('phoneCountryCode');
  };

  useEffect(() => {
    if (!isOpen) {
      setFormErrors({});
    }
  }, [isOpen]);

  if (!isOpen) {return null;}

  return createPortal(
    <div style={{
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      backgroundColor: 'rgba(0, 0, 0, 0.5)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      zIndex: 9999,
      padding: '20px',
      backdropFilter: 'blur(4px)'
    }}>
      <div style={{
        backgroundColor: 'var(--card)',
        borderRadius: '12px',
        width: '100%',
        maxWidth: '500px',
        maxHeight: '90vh',
        overflow: 'hidden',
        boxShadow: 'var(--shadow-xl)'
      }}>
        {/* Header */}
        <div style={{
          padding: '24px',
          borderBottom: '1px solid var(--border-primary)',
          backgroundColor: 'var(--bg-tertiary)'
        }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between'
          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
              <span className="material-symbols-outlined" style={{ fontSize: '28px', color: 'var(--accent)' }}>
                person_add
              </span>
              <div>
                <h2 style={{
                  margin: 0,
                  fontSize: '20px',
                  fontWeight: '700',
                  color: 'var(--text-primary)'
                }}>
                  {t('addTeamMember', { ns: 'settings' })}
                </h2>
                <p style={{
                  margin: '4px 0 0 0',
                  fontSize: '14px',
                  color: 'var(--text-muted)'
                }}>
                  {t('addTeamMemberDescription', { ns: 'settings' })}
                </p>
              </div>
            </div>
            <button
              onClick={onClose}
              style={{
                background: 'none',
                border: 'none',
                cursor: 'pointer',
                color: 'var(--text-muted)',
                padding: '4px',
                borderRadius: '4px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                transition: 'all var(--transition-base)'
              }}
              onMouseEnter={(e) => {
                e.target.style.backgroundColor = 'var(--bg-hover)';
                e.target.style.color = 'var(--text-primary)';
              }}
              onMouseLeave={(e) => {
                e.target.style.backgroundColor = 'transparent';
                e.target.style.color = 'var(--text-muted)';
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: '24px' }}>close</span>
            </button>
          </div>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} style={{ overflow: 'auto', maxHeight: 'calc(90vh - 140px)' }}>
          <div style={{ padding: '24px' }}>
            {/* Member Name */}
            <div style={{ marginBottom: '20px' }}>
              <label style={{
                display: 'flex',
                alignItems: 'center',
                gap: '8px',
                marginBottom: '8px',
                fontWeight: '600',
                color: 'var(--text-primary)',
                fontSize: '14px'
              }}>
                <span className="material-symbols-outlined" style={{ fontSize: '18px', color: 'var(--accent)' }}>
                  person
                </span>
                {t('fullName', { ns: 'settings' })} *
              </label>
              <input
                type="text"
                name="name"
                value={formData.name}
                onChange={handleInputChange}
                placeholder={t('enterFullName', { ns: 'settings' })}
                style={{
                  width: '100%',
                  padding: '12px 16px',
                  border: '1px solid var(--border-secondary)',
                  borderRadius: '8px',
                  fontSize: '14px',
                  backgroundColor: 'var(--bg-input)',
                  color: 'var(--text-primary)',
                  transition: 'border-color 0.2s ease, box-shadow 0.2s ease'
                }}
                onFocus={(e) => {
                  e.target.style.borderColor = 'var(--accent)';
                  e.target.style.boxShadow = '0 0 0 3px var(--accent-bg)';
                }}
                onBlur={(e) => {
                  e.target.style.borderColor = 'var(--border-secondary)';
                  e.target.style.boxShadow = 'none';
                }}
                required
              />
              {formErrors.name && (
                <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '8px' }}>
                  {formErrors.name}
                </p>
              )}
            </div>

            {/* Email */}
            <div style={{ marginBottom: '20px' }}>
              <label style={{
                display: 'flex',
                alignItems: 'center',
                gap: '8px',
                marginBottom: '8px',
                fontWeight: '600',
                color: 'var(--text-primary)',
                fontSize: '14px'
              }}>
                <span className="material-symbols-outlined" style={{ fontSize: '18px', color: 'var(--accent)' }}>
                  email
                </span>
                {t('emailAddress', { ns: 'settings' })} *
              </label>
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleInputChange}
                placeholder={t('emailPlaceholder', { ns: 'settings' })}
                style={{
                  width: '100%',
                  padding: '12px 16px',
                  border: '1px solid var(--border-secondary)',
                  borderRadius: '8px',
                  fontSize: '14px',
                  backgroundColor: 'var(--bg-input)',
                  color: 'var(--text-primary)',
                  transition: 'border-color 0.2s ease, box-shadow 0.2s ease'
                }}
                onFocus={(e) => {
                  e.target.style.borderColor = 'var(--accent)';
                  e.target.style.boxShadow = '0 0 0 3px var(--accent-bg)';
                }}
                onBlur={(e) => {
                  e.target.style.borderColor = 'var(--border-secondary)';
                  e.target.style.boxShadow = 'none';
                }}
                required
              />
              {formErrors.email && (
                <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '8px' }}>
                  {formErrors.email}
                </p>
              )}
            </div>

            {/* Phone Number */}
            <div style={{ marginBottom: '20px' }}>
              <label style={{
                display: 'flex',
                alignItems: 'center',
                gap: '8px',
                marginBottom: '8px',
                fontWeight: '600',
                color: 'var(--text-primary)',
                fontSize: '14px'
              }}>
                <span className="material-symbols-outlined" style={{ fontSize: '18px', color: 'var(--accent)' }}>
                  phone
                </span>
                {t('phoneNumber', { ns: 'settings' })} *
              </label>
              <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                <div style={{ position: 'relative', width: '160px', flexShrink: 0, minWidth: '160px' }}>
                  <span style={{
                    position: 'absolute',
                    left: '12px',
                    top: '50%',
                    transform: 'translateY(-50%)',
                    pointerEvents: 'none',
                    zIndex: 1,
                    display: 'flex',
                    alignItems: 'center'
                  }}>
                    <FlagIcon
                      countryCode={selectedPhoneCountry?.code}
                      size="1.1em"
                    />
                  </span>
                  <select
                    name="phoneCountryCode"
                    value={formData.phoneCountryCode}
                    onChange={handleInputChange}
                    style={{
                      width: '100%',
                      padding: '12px 20px 12px 38px',
                      borderRadius: '8px',
                      border: '1px solid var(--border-secondary)',
                      backgroundColor: 'var(--bg-input)',
                      color: 'var(--text-primary)',
                      appearance: 'none',
                      backgroundImage: 'url("data:image/svg+xml;charset=UTF-8,%3csvg xmlns=\'http://www.w3.org/2000/svg\' viewBox=\'0 0 24 24\' fill=\'none\' stroke=\'currentColor\' stroke-width=\'2\' stroke-linecap=\'round\' stroke-linejoin=\'round\'%3e%3cpolyline points=\'6 9 12 15 18 9\'%3e%3c/polyline%3e%3c/svg%3e")',
                      backgroundRepeat: 'no-repeat',
                      backgroundPosition: 'right 6px center',
                      backgroundSize: '10px',
                      cursor: 'pointer',
                      fontSize: '12px',
                      boxSizing: 'border-box'
                    }}
                  >
                    {countries.map((country) => (
                      <option key={country.code} value={country.dialCode} style={{ fontSize: '12px' }}>
                        {country.name.substring(0, 3).toUpperCase()} {country.dialCode}
                      </option>
                    ))}
                  </select>
                </div>
                <input
                  type="tel"
                  name="phoneNumber"
                  value={formData.phoneNumber}
                  onChange={handlePhoneChange}
                  placeholder="241234567"
                  style={{
                    flex: 1,
                    padding: '12px 16px',
                    border: '1px solid var(--border-secondary)',
                    borderRadius: '8px',
                    fontSize: '14px',
                    backgroundColor: 'var(--bg-input)',
                    color: 'var(--text-primary)',
                    transition: 'border-color 0.2s ease, box-shadow 0.2s ease'
                  }}
                  onFocus={(e) => {
                    e.target.style.borderColor = 'var(--accent)';
                    e.target.style.boxShadow = '0 0 0 3px var(--accent-bg)';
                  }}
                  onBlur={(e) => {
                    e.target.style.borderColor = 'var(--border-secondary)';
                    e.target.style.boxShadow = 'none';
                  }}
                  required
                />
              </div>
              {(formErrors.phoneNumber || formErrors.phoneCountryCode) && (
                <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '8px' }}>
                  {formErrors.phoneNumber || formErrors.phoneCountryCode}
                </p>
              )}
            </div>

            {/* Role Display (Constant) */}
            <div style={{ marginBottom: '20px' }}>
              <label style={{
                display: 'flex',
                alignItems: 'center',
                gap: '8px',
                marginBottom: '8px',
                fontWeight: '600',
                color: 'var(--text-primary)',
                fontSize: '14px'
              }}>
                <span className="material-symbols-outlined" style={{ fontSize: '18px', color: 'var(--accent)' }}>
                  admin_panel_settings
                </span>
                {t('role', { ns: 'settings' })}
              </label>
              <div style={{
                width: '100%',
                padding: '14px 16px',
                border: '1px solid var(--border-secondary)',
                borderRadius: '8px',
                fontSize: '14px',
                backgroundColor: 'var(--bg-secondary)',
                color: 'var(--text-primary)',
                fontWeight: '500',
                display: 'flex',
                alignItems: 'center',
                gap: '8px'
              }}>
                <span className="material-symbols-outlined" style={{ fontSize: '16px', color: 'var(--text-muted)' }}>
                  person
                </span>
                {t('member', { ns: 'settings' })}
              </div>
              <p style={{
                margin: '4px 0 0 0',
                fontSize: '12px',
                color: 'var(--text-muted)'
              }}>
                {t('memberDescription', { ns: 'settings', defaultValue: 'Standard team member with assigned permissions' })}
              </p>
            </div>
          </div>

          {/* Footer */}
          <div style={{
            padding: '20px 24px',
            borderTop: '1px solid var(--border-primary)',
            backgroundColor: 'var(--bg-tertiary)',
            display: 'flex',
            justifyContent: 'flex-end',
            gap: '12px'
          }}>
            <button
              type="button"
              onClick={onClose}
              style={{
                padding: '10px 20px',
                backgroundColor: 'var(--bg-input)',
                border: '1px solid var(--border-secondary)',
                borderRadius: '8px',
                fontSize: '14px',
                fontWeight: '500',
                color: 'var(--text-secondary)',
                cursor: 'pointer',
                transition: 'all 0.2s ease'
              }}
              onMouseEnter={(e) => {
                e.target.style.backgroundColor = 'var(--bg-hover)';
                e.target.style.borderColor = 'var(--border-primary)';
              }}
              onMouseLeave={(e) => {
                e.target.style.backgroundColor = 'var(--bg-input)';
                e.target.style.borderColor = 'var(--border-secondary)';
              }}
            >
              {t('cancel', { ns: 'settings' })}
            </button>
            <button
              type="submit"
              disabled={addTeamMemberMutation.isPending}
              style={{
                padding: '10px 20px',
                backgroundColor: addTeamMemberMutation.isPending ? 'var(--text-muted)' : 'var(--accent)',
                border: 'none',
                borderRadius: '8px',
                fontSize: '14px',
                fontWeight: '500',
                color: 'var(--text-inverse)',
                cursor: addTeamMemberMutation.isPending ? 'not-allowed' : 'pointer',
                display: 'inline-flex',
                alignItems: 'center',
                gap: '8px',
                transition: 'background-color 0.2s ease'
              }}
              onMouseEnter={(e) => {
                if (!addTeamMemberMutation.isPending) {e.target.style.backgroundColor = 'var(--accent-hover)';}
              }}
              onMouseLeave={(e) => {
                if (!addTeamMemberMutation.isPending) {e.target.style.backgroundColor = 'var(--accent)';}
              }}
            >
              {addTeamMemberMutation.isPending ? (
                <>
                  <div style={{
                    width: '14px',
                    height: '14px',
                    border: '2px solid transparent',
                    borderTop: '2px solid currentColor',
                    borderRadius: '50%',
                    animation: 'spin 1s linear infinite'
                  }} />
                  {t('adding', { ns: 'settings' })}
                </>
              ) : (
                <>
                  <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>person_add</span>
                  {t('addMember', { ns: 'settings' })}
                </>
              )}
            </button>
          </div>
        </form>

        {/* Loading overlay popup */}
        {addTeamMemberMutation.isPending && (
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(0, 0, 0, 0.5)',
            backdropFilter: 'blur(4px)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 10000
          }}>
            <div style={{
              backgroundColor: 'var(--card)',
              borderRadius: '16px',
              padding: '48px',
              boxShadow: 'var(--shadow-xl)',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              minWidth: '120px',
              minHeight: '120px'
            }}>
              <LoadingSpinner size="large" />
            </div>
          </div>
        )}
      </div>

      <style>{`
        @media (max-width: 1024px) {
          div[style*="maxWidth: '500px'"] {
            max-width: min(90vw, 460px) !important;
          }
          div[style*="padding: '24px'"] {
            padding: 20px !important;
          }
          div[style*="padding: '20px 24px'"] {
            padding: 18px 20px !important;
          }
        }

        @media (max-width: 768px) {
          div[style*="maxWidth: '500px'"] {
            max-width: min(95vw, 420px) !important;
          }
          div[style*="padding: '24px'"] {
            padding: 18px !important;
          }
          div[style*="padding: '20px 24px'"] {
            padding: 16px !important;
          }
          h2[style*="fontSize: '20px'"] {
            font-size: 18px !important;
          }
          div[style*="marginBottom: '20px'"] {
            margin-bottom: 16px !important;
          }
        }

        @media (max-width: 480px) {
          div[style*="maxWidth: '500px'"] {
            max-width: calc(100vw - 16px) !important;
          }
          div[style*="padding: '24px'"] {
            padding: 12px !important;
          }
          div[style*="padding: '20px 24px'"] {
            padding: 12px !important;
          }
          h2[style*="fontSize: '20px'"] {
            font-size: 16px !important;
          }
          p[style*="fontSize: '14px'"] {
            font-size: 12px !important;
          }
          div[style*="marginBottom: '20px'"] {
            margin-bottom: 14px !important;
          }
          input[style*="padding: '12px 16px'"] {
            padding: 10px 12px !important;
            font-size: 14px !important;
          }
          button[style*="padding: '10px 20px'"] {
            padding: 8px 14px !important;
            font-size: 13px !important;
          }
          div[style*="gap: '12px'"] {
            gap: 8px !important;
          }
          div[style*="gap: '8px'"] {
            gap: 6px !important;
          }
        }
      `}</style>
    </div>,
    document.body
  );
};

export default AddTeamMemberModal;
