/**
 * Business Settings Page
 * 
 * Main settings navigation for business users. Provides tabs for profile,
 * business information, payment methods, security, verification, API access,
 * and team management. Routes users to individual settings if incorrect user type.
 */

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate, useLocation, Outlet } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import Profile from './Profile';
import Business from './Business';
import PaymentMethods from './PaymentMethods';
import Security from './Security';
import Verification from './Verification';
import API from './API';
import Team from './Team';
import ChargeBearer from './ChargeBearer';
import '/styles/pages/IndividualSettings.css';

const Settings = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const location = useLocation();

  // Determine active section from URL
  const getActiveSectionFromUrl = useCallback(() => {
    const path = location.pathname;
    if (path.includes('/verification')) {
      return 'verification';
    }
    // Check for hash or query params for other sections
    const hash = location.hash.replace('#', '');
    if (hash && ['profile', 'business', 'payment-methods', 'security', 'verification', 'api', 'team', 'charge-bearer'].includes(hash)) {
      return hash;
    }
    // Default to profile if no specific section in URL
    return 'profile';
  }, [location.pathname, location.hash]);

  const [activeSection, setActiveSection] = useState(() => {
    const path = location.pathname;
    if (path.includes('/verification')) {
      return 'verification';
    }
    const hash = location.hash.replace('#', '');
    if (hash && ['profile', 'business', 'payment-methods', 'security', 'verification', 'api', 'team', 'charge-bearer'].includes(hash)) {
      return hash;
    }
    return 'profile';
  });

  const getCurrentUserType = useCallback(() => {
    try {
      const userData = JSON.parse(localStorage.getItem('userData') || '{}');
      const storedUserType = localStorage.getItem('userType');
      const userType = (userData?.userType || userData?.user_type || userData?.usertype || storedUserType || 'individual').toLowerCase();
      return userType === 'business' ? 'business_contact' : userType;
    } catch (error) {
      // If JSON parsing fails, return default
      const storedUserType = localStorage.getItem('userType');
      const userType = (storedUserType || 'individual').toLowerCase();
      return userType === 'business' ? 'business_contact' : userType;
    }
  }, []);

  const currentUserType = useMemo(() => getCurrentUserType(), [getCurrentUserType]);

  useEffect(() => {
    if (!['business', 'business_contact'].includes(currentUserType)) {
      navigate('/settings/individual');
      return;
    }
  }, [currentUserType, navigate]);

  // Update active section when URL changes
  useEffect(() => {
    const sectionFromUrl = getActiveSectionFromUrl();
    if (sectionFromUrl !== activeSection) {
      setActiveSection(sectionFromUrl);
    }
  }, [location.pathname, location.hash, getActiveSectionFromUrl, activeSection]);

  useEffect(() => {
    if (['business', 'business_contact'].includes(currentUserType)) {
      // Only set default if no section is specified in URL
      if (location.pathname === '/settings/business' && !location.hash) {
        const storedTab = localStorage.getItem('businessSettingsActiveTab');
        if (storedTab && ['profile', 'business', 'payment-methods', 'security', 'verification', 'api', 'team', 'charge-bearer'].includes(storedTab)) {
          setActiveSection(storedTab);
        } else {
          setActiveSection('security');
        }
      }
    }
  }, [currentUserType, location.pathname, location.hash]);

  // Handle section change - update URL and state
  const handleSectionChange = (sectionKey) => {
    setActiveSection(sectionKey);
    if (['business', 'business_contact'].includes(currentUserType)) {
      localStorage.setItem('businessSettingsActiveTab', sectionKey);
    }
    // For verification, use the nested route
    if (sectionKey === 'verification') {
      navigate('/settings/business/verification', { replace: true });
    } else {
      // For other sections, use hash navigation
      navigate(`/settings/business#${sectionKey}`, { replace: true });
    }
  };

  const handleTabChange = (newSection) => {
    handleSectionChange(newSection);
  };

  const renderContent = () => {
    switch (activeSection) {
      case 'profile':
        return <Profile />;
      case 'business':
        return <Business />;
      case 'payment-methods':
        return <PaymentMethods />;
      case 'security':
        return <Security />;
      case 'verification':
        return <Verification />;
      case 'charge-bearer':
        return <ChargeBearer />;
      case 'api':
        return <API />;
      case 'team':
        return <Team />;
      default:
        return <Profile />;
    }
  };

  const sections = useMemo(() => {
    const allSections = [
      { key: 'profile', label: t('profile', { ns: 'settings' }), icon: 'person' },
      { key: 'business', label: t('business', { ns: 'settings' }), icon: 'business' },
      { key: 'payment-methods', label: t('settlementMethods', { ns: 'settings' }), icon: 'payment' },
      { key: 'security', label: t('security', { ns: 'settings' }), icon: 'security' },
      { key: 'verification', label: t('verification', { ns: 'settings' }), icon: 'verified_user' },
      { key: 'api', label: t('apiManagement', { ns: 'settings' }), icon: 'api' },
      { key: 'team', label: t('teamManagement', { ns: 'settings' }), icon: 'group' },
      { key: 'charge-bearer', label: t('chargeBearer', { ns: 'settings', defaultValue: 'Charge Bearer' }), icon: 'receipt_long' },
    ];

    // Requirement 2: For team members, only show the Profile tab
    if (currentUserType === 'business_member') {
      return allSections.filter(s => s.key === 'profile');
    }
    
    return allSections;
  }, [t, currentUserType]);

  const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);
  const [showMobileMenu, setShowMobileMenu] = useState(false);

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth <= 768);
      if (window.innerWidth > 768) {
        setShowMobileMenu(false);
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const activeSectionLabel = sections.find(s => s.key === activeSection)?.label || '';

  return (
    <div className="settings-page-container">

      {/* Mobile Dropdown Menu */}
      {isMobile && (
        <div className="settings-mobile-select-wrapper" data-tour="settings-navigation">
          <button
            className="settings-mobile-select"
            onClick={() => setShowMobileMenu(!showMobileMenu)}
          >
            <span className="material-symbols-outlined" style={{ fontSize: 18 }}>
              {sections.find(s => s.key === activeSection)?.icon || 'settings'}
            </span>
            <span>{activeSectionLabel}</span>
            <span className="material-symbols-outlined" style={{ fontSize: 18, marginLeft: 'auto' }}>
              {showMobileMenu ? 'expand_less' : 'expand_more'}
            </span>
          </button>
          {showMobileMenu && (
            <div className="settings-mobile-menu">
              {sections.map((section) => (
                <button
                  key={section.key}
                  onClick={() => {
                    handleSectionChange(section.key);
                    setShowMobileMenu(false);
                  }}
                  className={`settings-mobile-menu-item ${activeSection === section.key ? 'active' : ''}`}
                >
                  <span className="material-symbols-outlined">{section.icon}</span>
                  {section.label}
                </button>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Desktop: sidebar + content layout */}
      {!isMobile ? (
        <div className="settings-layout">
          {/* Left sidebar nav */}
          <aside className="settings-sidebar" data-tour="settings-navigation">
            <div className="settings-sidebar__title">{t('businessSettings', { ns: 'settings' })}</div>
            <nav className="settings-sidebar__nav">
              {sections.map((section) => (
                <button
                  key={section.key}
                  onClick={() => handleSectionChange(section.key)}
                  className={`settings-sidebar__item ${activeSection === section.key ? 'active' : ''}`}
                >
                  <span className="material-symbols-outlined">{section.icon}</span>
                  <span>{section.label}</span>
                </button>
              ))}
            </nav>
          </aside>

          {/* Right content */}
          <div className="settings-content" data-tour={`settings-${activeSection}`}>
            {location.pathname.includes('/verification') ? (
              <Outlet />
            ) : (
              renderContent()
            )}
          </div>
        </div>
      ) : (
        /* Mobile: full-width content */
        <div className="settings-content" data-tour={`settings-${activeSection}`}>
          {location.pathname.includes('/verification') ? (
            <Outlet />
          ) : (
            renderContent()
          )}
        </div>
      )}
    </div>
  );
};

export default Settings;
