/**
 * Team Creation Modal Component
 * 
 * Modal dialog for creating new teams with name and page access permissions.
 * Allows selecting which application pages the team can access and handles
 * team creation via team service.
 */

import React, { useState, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { teamService } from '@/features/settings/services';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { LoadingSpinner } from '@/shared/components';
import { createTeamSchema } from '@/shared/utils/validation/settingsSchemas.js';
import { mapFieldErrors } from '@/shared/utils/validation/helpers.js';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import logger from '@/shared/utils/logger.js';

const TeamCreationModal = ({ isOpen, onClose, businessId, onTeamCreated, teamToEdit, onTeamUpdated }) => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const [formData, setFormData] = useState({
    name: '',
    pageAccess: []
  });

  // Update form data when teamToEdit changes
  React.useEffect(() => {
    if (isOpen) {
      if (teamToEdit) {
        setFormData({
          name: teamToEdit.name || '',
          pageAccess: teamToEdit.page_access || teamToEdit.menus || []
        });
      } else {
        setFormData({
          name: '',
          pageAccess: []
        });
      }
    }
  }, [isOpen, teamToEdit]);
  const [formErrors, setFormErrors] = useState({});

  // Use React Query mutation for creating team
  const createTeamMutation = useMutation({
    mutationFn: async (teamData) => {
      return await teamService.createTeam(businessId, teamData);
    },
    invalidateQueries: [
      queryKeys.settings.team(),
      ['team', 'details'],
    ],
    onSuccess: (createdTeam) => {
      success(t('teamCreatedSuccessfully', { ns: 'settings' }));
      // Reset form
      setFormData({ name: '', pageAccess: [] });
      setFormErrors({});
      if (typeof onTeamCreated === 'function') {onTeamCreated(createdTeam);}
      if (typeof onClose === 'function') {onClose();}
    },
    onError: (err) => {
      logger.error('Error creating team', { error: err });
      showError(err.message || t('failedToCreateTeam', { ns: 'settings' }));
    },
  });

  // Use React Query mutation for updating team
  const updateTeamMutation = useMutation({
    mutationFn: async ({ teamId, teamData }) => {
      if (!teamId) {
        throw new Error('Team ID is required for update');
      }
      return await teamService.updateTeam(businessId, teamId, teamData);
    },
    invalidateQueries: [
      queryKeys.settings.team(),
      ['team', 'details'],
    ],
    onSuccess: (updatedTeam) => {
      success(t('teamUpdatedSuccessfully', { ns: 'settings', defaultValue: 'Team updated successfully' }));
      setFormErrors({});
      if (typeof onTeamUpdated === 'function') {onTeamUpdated(updatedTeam);}
      if (typeof onClose === 'function') {onClose();}
    },
    onError: (err) => {
      logger.error('Error updating team', { error: err });
      showError(err.message || t('failedToUpdateTeam', { ns: 'settings', defaultValue: 'Failed to update team' }));
    },
  });

  const availablePages = useMemo(() => [
    { id: 'dashboard', name: t('dashboard', { ns: 'common' }), description: t('pageDescriptionDashboard', { ns: 'settings' }) },
    { id: 'collections', name: t('collections', { ns: 'common' }), description: t('pageDescriptionCollections', { ns: 'settings' }) },
    { id: 'disbursements', name: t('disbursements', { ns: 'common' }), description: t('pageDescriptionDisbursements', { ns: 'settings' }) },
    { id: 'payroll', name: t('payroll', { ns: 'common' }), description: t('pageDescriptionPayroll', { ns: 'settings' }) },
    { id: 'reports', name: t('reports', { ns: 'common' }), description: t('pageDescriptionReports', { ns: 'settings' }) },
    { id: 'security', name: t('security', { ns: 'settings' }), description: t('pageDescriptionSecurity', { ns: 'settings' }) },
    { id: 'utilities', name: t('utilities', { ns: 'common' }), description: t('pageDescriptionUtilities', { ns: 'settings' }) }
  ], [t]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    if (formErrors[name]) {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next[name];
        return next;
      });
    }
  };

  const handlePageToggle = (pageId) => {
    setFormData(prev => ({
      ...prev,
      pageAccess: prev.pageAccess.includes(pageId)
        ? prev.pageAccess.filter(id => id !== pageId)
        : [...prev.pageAccess, pageId]
    }));
    if (formErrors.pageAccess) {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next.pageAccess;
        return next;
      });
    }
  };

  const handleSelectAll = () => {
    setFormData(prev => ({
      ...prev,
      pageAccess: availablePages.map(page => page.id)
    }));
    if (formErrors.pageAccess) {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next.pageAccess;
        return next;
      });
    }
  };

  const handleDeselectAll = () => {
    setFormData(prev => ({
      ...prev,
      pageAccess: []
    }));
    if (formErrors.pageAccess) {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next.pageAccess;
        return next;
      });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const schema = createTeamSchema(t);
    const validation = schema.safeParse({
      name: formData.name,
      pageAccess: formData.pageAccess,
    });

    if (!validation.success) {
      const errors = mapFieldErrors(validation.error);
      setFormErrors(errors);
      const message = Object.values(errors)[0] || t('pleaseFillInAllFields', { ns: 'settings' });
      showError(message);
      return;
    }

    const validated = validation.data;

    if (!businessId) {
      showError(t('businessIdMissing', { ns: 'settings' }));
      return;
    }

    // ✅ Explicitly ensure menus is an array before sending
    const teamData = {
      name: validated.name.trim(),
      menus: Array.isArray(validated.pageAccess) ? [...validated.pageAccess] : [],
      status: 'active',
    };
    logger.debug('Prepared teamData before API call', { teamData, formDataPageAccess: formData.pageAccess, menus: teamData.menus });

    if (teamToEdit && teamToEdit.id) {
      updateTeamMutation.mutate({ teamId: teamToEdit.id, teamData });
    } else {
      createTeamMutation.mutate(teamData);
    }
  };

  const isPending = createTeamMutation.isPending || updateTeamMutation.isPending;


  if (!isOpen) {return null;}

  return createPortal(
    <div style={{
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      backgroundColor: 'rgba(0, 0, 0, 0.5)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      zIndex: 9999,
      padding: '20px',
      backdropFilter: 'blur(4px)'
    }}>
      <div style={{
        backgroundColor: 'var(--card)',
        borderRadius: '12px',
        width: '100%',
        maxWidth: '600px',
        maxHeight: '90vh',
        overflow: 'hidden',
        boxShadow: 'var(--shadow-xl)'
      }}>
        {/* Header */}
        <div style={{
          padding: '24px',
          borderBottom: '1px solid var(--border-primary)',
          backgroundColor: 'var(--bg-tertiary)'
        }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between'
          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
              <span className="material-symbols-outlined" style={{ fontSize: '28px', color: 'var(--accent)' }}>
                group_add
              </span>
              <div>
                <h2 style={{
                  margin: 0,
                  fontSize: '20px',
                  fontWeight: '700',
                  color: 'var(--text-primary)'
                }}>
                  {teamToEdit ? t('editTeam', { ns: 'settings', defaultValue: 'Edit Team' }) : t('createNewTeam', { ns: 'settings' })}
                </h2>
                <p style={{
                  margin: '4px 0 0 0',
                  fontSize: '14px',
                  color: 'var(--text-muted)'
                }}>
                  {teamToEdit ? t('editTeamDescription', { ns: 'settings', defaultValue: 'Update team details and permissions' }) : t('createNewTeamDescription', { ns: 'settings' })}
                </p>
              </div>
            </div>
            <button
              onClick={onClose}
              style={{
                background: 'none',
                border: 'none',
                cursor: 'pointer',
                color: 'var(--text-muted)',
                padding: '4px',
                borderRadius: '4px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                transition: 'all var(--transition-base)'
              }}
              onMouseEnter={(e) => {
                e.target.style.backgroundColor = 'var(--bg-hover)';
                e.target.style.color = 'var(--text-primary)';
              }}
              onMouseLeave={(e) => {
                e.target.style.backgroundColor = 'transparent';
                e.target.style.color = 'var(--text-muted)';
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: '24px' }}>close</span>
            </button>
          </div>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} style={{ overflow: 'auto', maxHeight: 'calc(90vh - 140px)' }}>
          <div style={{ padding: '24px' }}>
            {/* Team Name */}
            <div style={{ marginBottom: '24px' }}>
              <label style={{
                display: 'flex',
                alignItems: 'center',
                gap: '8px',
                marginBottom: '8px',
                fontWeight: '600',
                color: 'var(--text-primary)',
                fontSize: '14px'
              }}>
                <span className="material-symbols-outlined" style={{ fontSize: '18px', color: 'var(--accent)' }}>
                  badge
                </span>
                {t('teamName', { ns: 'settings' })} *
              </label>
              <input
                type="text"
                name="name"
                value={formData.name}
                onChange={handleInputChange}
                placeholder={t('enterTeamName', { ns: 'settings' })}
                style={{
                  width: '100%',
                  padding: '12px 16px',
                  border: '2px solid var(--border-secondary)',
                  borderRadius: '8px',
                  fontSize: '14px',
                  backgroundColor: 'var(--bg-input)',
                  color: 'var(--text-primary)',
                  transition: 'border-color 0.2s ease, box-shadow 0.2s ease'
                }}
                onFocus={(e) => {
                  e.target.style.borderColor = 'var(--accent)';
                  e.target.style.boxShadow = '0 0 0 3px var(--accent-bg)';
                }}
                onBlur={(e) => {
                  e.target.style.borderColor = 'var(--border-secondary)';
                  e.target.style.boxShadow = 'none';
                }}
                required
              />
              {formErrors.name && (
                <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '8px' }}>
                  {formErrors.name}
                </p>
              )}
            </div>

            {/* Page Access Selection */}
            <div style={{ marginBottom: '24px' }}>
              <div style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
                marginBottom: '16px'
              }}>
                <label style={{
                  fontWeight: '600',
                  color: 'var(--text-primary)',
                  fontSize: '14px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <span className="material-symbols-outlined" style={{ fontSize: '18px', color: 'var(--accent)' }}>
                    lock
                  </span>
                  {t('pageAccessPermissions', { ns: 'settings' })} *
                </label>
                <div style={{ display: 'flex', gap: '8px' }}>
                  <button
                    type="button"
                    onClick={handleSelectAll}
                    style={{
                      padding: '4px 12px',
                      backgroundColor: 'var(--bg-tertiary)',
                      border: '1px solid var(--border-primary)',
                      borderRadius: '6px',
                      fontSize: '12px',
                      color: 'var(--text-secondary)',
                      cursor: 'pointer',
                      transition: 'background-color 0.2s ease'
                    }}
                    onMouseEnter={(e) => e.target.style.backgroundColor = 'var(--bg-hover)'}
                    onMouseLeave={(e) => e.target.style.backgroundColor = 'var(--bg-tertiary)'}
                  >
                    {t('selectAll', { ns: 'settings' })}
                  </button>
                  <button
                    type="button"
                    onClick={handleDeselectAll}
                    style={{
                      padding: '4px 12px',
                      backgroundColor: 'var(--bg-tertiary)',
                      border: '1px solid var(--border-primary)',
                      borderRadius: '6px',
                      fontSize: '12px',
                      color: 'var(--text-secondary)',
                      cursor: 'pointer',
                      transition: 'background-color 0.2s ease'
                    }}
                    onMouseEnter={(e) => e.target.style.backgroundColor = 'var(--bg-hover)'}
                    onMouseLeave={(e) => e.target.style.backgroundColor = 'var(--bg-tertiary)'}
                  >
                    {t('deselectAll', { ns: 'settings' })}
                  </button>
                </div>
              </div>

              <div style={{
                border: '1px solid var(--border-primary)',
                borderRadius: '8px',
                maxHeight: '300px',
                overflow: 'auto'
              }}>
                {availablePages.map((page) => (
                  <div
                    key={page.id}
                    onClick={() => handlePageToggle(page.id)}
                    style={{
                      padding: '16px',
                      borderBottom: '1px solid var(--border-primary)',
                      cursor: 'pointer',
                      backgroundColor: formData.pageAccess.includes(page.id) ? 'var(--info-bg)' : 'var(--card)',
                      borderLeft: formData.pageAccess.includes(page.id) ? '4px solid var(--accent)' : '4px solid transparent',
                      transition: 'all 0.2s ease'
                    }}
                    onMouseEnter={(e) => {
                      if (!formData.pageAccess.includes(page.id)) {
                        e.target.style.backgroundColor = 'var(--bg-hover)';
                      }
                    }}
                    onMouseLeave={(e) => {
                      if (!formData.pageAccess.includes(page.id)) {
                        e.target.style.backgroundColor = 'var(--card)';
                      }
                    }}
                  >
                    <div style={{ display: 'flex', alignItems: 'flex-start', gap: '12px' }}>
                      <input
                        type="checkbox"
                        checked={formData.pageAccess.includes(page.id)}
                        onChange={() => handlePageToggle(page.id)}
                        style={{
                          marginTop: '2px',
                          width: '16px',
                          height: '16px',
                          accentColor: 'var(--accent)'
                        }}
                      />
                      <div style={{ flex: 1 }}>
                        <div style={{
                          fontWeight: '600',
                          color: 'var(--text-primary)',
                          marginBottom: '4px'
                        }}>
                          {page.name}
                        </div>
                        <div style={{
                          fontSize: '13px',
                          color: 'var(--text-muted)',
                          lineHeight: '1.4'
                        }}>
                          {page.description}
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              {formErrors.pageAccess && (
                <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '12px' }}>
                  {formErrors.pageAccess}
                </p>
              )}

              {formData.pageAccess.length > 0 && (
                <div style={{
                  marginTop: '12px',
                  padding: '8px 12px',
                  backgroundColor: 'var(--info-bg)',
                  borderRadius: '6px',
                  border: '1px solid var(--info)'
                }}>
                  <div style={{
                    fontSize: '12px',
                    color: 'var(--accent)',
                    fontWeight: '500'
                  }}>
                    {formData.pageAccess.length} {t('pagesSelected', { ns: 'settings' })}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Footer */}
          <div style={{
            padding: '20px 24px',
            borderTop: '1px solid var(--border-primary)',
            backgroundColor: 'var(--bg-tertiary)',
            display: 'flex',
            justifyContent: 'flex-end',
            gap: '12px'
          }}>
            <button
              type="button"
              onClick={onClose}
              style={{
                padding: '10px 20px',
                backgroundColor: 'var(--bg-input)',
                border: '1px solid var(--border-secondary)',
                borderRadius: '8px',
                fontSize: '14px',
                fontWeight: '500',
                color: 'var(--text-secondary)',
                cursor: 'pointer',
                transition: 'all 0.2s ease'
              }}
              onMouseEnter={(e) => {
                e.target.style.backgroundColor = 'var(--bg-hover)';
                e.target.style.borderColor = 'var(--border-secondary)';
              }}
              onMouseLeave={(e) => {
                e.target.style.backgroundColor = 'var(--bg-input)';
                e.target.style.borderColor = 'var(--border-secondary)';
              }}
            >
              {t('cancel', { ns: 'settings' })}
            </button>
            <button
              type="submit"
              disabled={isPending}
              style={{
                padding: '10px 20px',
                backgroundColor: isPending ? 'var(--text-muted)' : 'var(--accent)',
                border: 'none',
                borderRadius: '8px',
                fontSize: '14px',
                fontWeight: '500',
                color: 'var(--text-inverse)',
                cursor: isPending ? 'not-allowed' : 'pointer',
                display: 'inline-flex',
                alignItems: 'center',
                gap: '8px',
                transition: 'background-color 0.2s ease'
              }}
              onMouseEnter={(e) => {
                if (!isPending) {e.target.style.backgroundColor = 'var(--accent-hover)';}
              }}
              onMouseLeave={(e) => {
                if (!isPending) {e.target.style.backgroundColor = 'var(--accent)';}
              }}
            >
              {isPending ? (
                <>
                  <div style={{
                    width: '14px',
                    height: '14px',
                    border: '2px solid transparent',
                    borderTop: '2px solid currentColor',
                    borderRadius: '50%',
                    animation: 'spin 1s linear infinite'
                  }} />
                  {teamToEdit ? t('updating', { ns: 'settings', defaultValue: 'Updating...' }) : t('creating', { ns: 'settings' })}
                </>
              ) : (
                <>
                  <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>{teamToEdit ? 'save' : 'add'}</span>
                  {teamToEdit ? t('updateTeam', { ns: 'settings', defaultValue: 'Update Team' }) : t('createTeam', { ns: 'settings' })}
                </>
              )}
            </button>
          </div>
        </form>

        {/* Loading overlay popup */}
        {isPending && (
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(0, 0, 0, 0.5)',
            backdropFilter: 'blur(4px)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 10000
          }}>
            <div style={{
              backgroundColor: 'var(--card)',
              borderRadius: '16px',
              padding: '48px',
              boxShadow: 'var(--shadow-xl)',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              minWidth: '120px',
              minHeight: '120px'
            }}>
              <LoadingSpinner size="large" />
            </div>
          </div>
        )}
      </div>

      <style>{`
        @media (max-width: 1024px) {
          div[style*="maxWidth: '600px'"] {
            max-width: min(90vw, 560px) !important;
          }
          div[style*="padding: '24px'"] {
            padding: 20px !important;
          }
          div[style*="padding: '20px 24px'"] {
            padding: 18px 20px !important;
          }
        }

        @media (max-width: 768px) {
          div[style*="maxWidth: '600px'"] {
            max-width: min(95vw, 500px) !important;
          }
          div[style*="padding: '24px'"] {
            padding: 18px !important;
          }
          div[style*="padding: '20px 24px'"] {
            padding: 16px !important;
          }
          h2[style*="fontSize: '20px'"] {
            font-size: 18px !important;
          }
          div[style*="marginBottom: '24px'"] {
            margin-bottom: 18px !important;
          }
          div[style*="marginBottom: '20px'"] {
            margin-bottom: 16px !important;
          }
        }

        @media (max-width: 480px) {
          div[style*="maxWidth: '600px'"] {
            max-width: calc(100vw - 16px) !important;
          }
          div[style*="padding: '24px'"] {
            padding: 12px !important;
          }
          div[style*="padding: '20px 24px'"] {
            padding: 12px !important;
          }
          h2[style*="fontSize: '20px'"] {
            font-size: 16px !important;
          }
          p[style*="fontSize: '14px'"] {
            font-size: 12px !important;
          }
          div[style*="marginBottom: '24px'"] {
            margin-bottom: 16px !important;
          }
          div[style*="marginBottom: '20px'"] {
            margin-bottom: 14px !important;
          }
          input[style*="padding: '12px 16px'"] {
            padding: 10px 12px !important;
            font-size: 14px !important;
          }
          button[style*="padding: '10px 20px'"] {
            padding: 8px 14px !important;
            font-size: 13px !important;
          }
          div[style*="padding: '16px'"] {
            padding: 12px !important;
          }
          div[style*="gap: '12px'"] {
            gap: 8px !important;
          }
        }
      `}</style>
    </div>,
    document.body
  );
};

export default TeamCreationModal;
