/**
 * API Settings Page
 * 
 * Manages API key generation and management for business users. Allows
 * creation, viewing, and copying of API keys for integration with external systems.
 */

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { Copy, Trash2, RefreshCw, Check, Key, AlertTriangle, Info, X } from 'lucide-react';
import { toast } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import '/styles/pages/APIPage.css';
import { apiService } from '@/features/settings/services/apiService.js';
import { useMutation, useQuery } from '@/shared/hooks';
import logger from '@/shared/utils/logger.js';

const API = () => {
  const { t } = useTranslation();
  const [copiedKey, setCopiedKey] = useState(null);
  const [newCredential, setNewCredential] = useState(null);
  // Load removed key IDs from localStorage on mount
  const [removedKeyIds, setRemovedKeyIds] = useState(() => {
    try {
      const stored = localStorage.getItem('removedApiKeyIds');
      return stored ? JSON.parse(stored) : [];
    } catch (e) {
      return [];
    }
  });
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [keyToDelete, setKeyToDelete] = useState(null);

  // Save removed key IDs to localStorage whenever they change
  useEffect(() => {
    try {
      localStorage.setItem('removedApiKeyIds', JSON.stringify(removedKeyIds));
    } catch (e) {
      logger.error('Failed to save removed API key IDs to localStorage', { error: e });
    }
  }, [removedKeyIds]);

  // Use React Query to load API keys with automatic caching and refetching
  const { data: apiKeysData, isLoading: isLoadingKeys } = useQuery({
    queryKey: ['api', 'keys'],
    queryFn: () => apiService.getApiKeys(),
    enabled: true,
    staleTime: 2 * 60 * 1000, // 2 minutes
    refetchOnWindowFocus: false, // Prevent automatic refetch on focus to avoid multiple calls
    select: (response) => {
      // API now returns: { code: "00", message: "...", data: { id, user_id, app_id, created_at, updated_at, status } }
      // Handle single object response - wrap in array for display consistency
      if (response?.code === '00' && response?.data) {
        const credential = response.data;
        return [{
          id: credential.id,
          user_id: credential.user_id,
          app_id: credential.app_id,
          status: credential.status,
          created_at: credential.created_at,
          updated_at: credential.updated_at,
          description: 'API Credentials'
        }];
      }
      // If no data or error code, return empty array
      return [];
    },
    onError: (error) => {
      logger.error('Error loading API keys', { error });
      // Don't show error toast if it's just that no credentials exist yet
      if (error.message && !error.message.includes('404') && !error.message.includes('not found')) {
        toast.error(error.message || t('failedToLoadApiKeys', { ns: 'settings', defaultValue: 'Failed to load API keys' }));
      }
    },
  });

  // Filter out removed keys from display
  const apiKeys = (apiKeysData || []).filter(key => !removedKeyIds.includes(key.id));

  // Check current API credential status - AUTOMATIC on load + MANUAL with button
  const { data: statusData, refetch: checkStatus, isLoading: isLoadingStatus } = useQuery({
    queryKey: ['api', 'key-status'],
    queryFn: () => apiService.checkCredentialStatus(),
    enabled: true, // Automatic on page load
    staleTime: 60 * 1000,
    refetchOnWindowFocus: false,
    select: (response) => response?.data?.status || 'N/A', // Default to N/A if unable to check
    onError: (error) => {
      logger.error('Error checking API credential status', { error });
      // Don't show error toast for status check failures
    },
  });

  const credentialStatus = statusData || 'N/A';

  // Manual status check function
  const handleCheckStatus = () => {
    checkStatus();
  };

  // Use React Query mutation for generating API keys
  const generateApiKeyMutation = useMutation({
    mutationFn: async () => {
      // Generate/rotate credentials using POST endpoint
      return await apiService.generateKey();
    },
    invalidateQueries: [
      ['api', 'keys'],
      ['api', 'key-status'], // Also invalidate status to refresh it
    ],
    onSuccess: (response) => {
      logger.debug('API key generation response', { response });
      
      // Handle both response codes - check for '01' (created) and '00' (success)
      if ((response?.code === '00' || response?.code === '01') && response?.data) {
        const { appId, appSecret } = response.data;
        logger.debug('Extracted credentials:', { appId, appSecret });
        
        if (appId && appSecret) {
          setNewCredential({ appId, appSecret });
          toast.success(t('apiKeyGeneratedSuccessfully', { ns: 'settings' }));
          // Auto-check status after successful generation
          setTimeout(() => checkStatus(), 500);
        } else {
          logger.error('Missing appId or appSecret in response data');
          toast.error(t('incompleteApiResponse', { ns: 'settings', defaultValue: 'Incomplete API response' }));
        }
        // Reset removed keys so new/updated key is visible
        setRemovedKeyIds([]);
      } else {
        logger.error('Unexpected response format:', response);
        toast.error(response?.message || t('failedToGenerateApiKey', { ns: 'settings' }));
      }
    },
    onError: (err) => {
      logger.error('Error generating API key', { error: err });
      toast.error(err.message || t('failedToGenerateApiKey', { ns: 'settings' }));
    },
  });

  const generateApiKey = () => {
    generateApiKeyMutation.mutate();
  };

  const dismissNewCredential = () => {
    setNewCredential(null);
  };

  const copyToClipboard = (text, type = 'key') => {
    navigator.clipboard.writeText(text);
    setCopiedKey(text);
    const message = type === 'app_id' 
      ? t('appIdCopied', { ns: 'settings', defaultValue: 'App ID copied to clipboard' })
      : t('apiKeyCopiedToClipboard', { ns: 'settings', defaultValue: 'API key copied to clipboard' });
    toast.success(message);
    setTimeout(() => setCopiedKey(null), 2000);
  };

  const handleDeleteClick = (id) => {
    setKeyToDelete(id);
    setShowDeleteConfirm(true);
  };

  const confirmDelete = () => {
    if (keyToDelete) {
      setRemovedKeyIds(prev => {
        const updated = [...prev, keyToDelete];
        // Save to localStorage immediately
        try {
          localStorage.setItem('removedApiKeyIds', JSON.stringify(updated));
        } catch (e) {
          logger.error('Failed to save removed API key IDs', { error: e });
        }
        return updated;
      });
      toast.success(t('keyRemovedFromDisplay', { ns: 'settings', defaultValue: 'API key removed from view' }));
      setShowDeleteConfirm(false);
      setKeyToDelete(null);
    }
  };

  const cancelDelete = () => {
    setShowDeleteConfirm(false);
    setKeyToDelete(null);
  };

  // API keys are now loaded via React Query (useQuery hook above)

  return (
    <div className="invoices-card">
      <div className="card-head">
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
          <div style={{
            width: '56px',
            height: '56px',
            borderRadius: '14px',
            background: 'linear-gradient(135deg, var(--accent) 0%, var(--accent-hover) 100%)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            boxShadow: 'var(--shadow-md)'
          }}>
            <span className="material-symbols-outlined" style={{ fontSize: '32px', color: 'white' }}>
              api
            </span>
          </div>
          <div>
            <h3 style={{ margin: 0, fontSize: '24px', fontWeight: '700', color: 'var(--text-primary)' }}>
              {t('apiManagement', { ns: 'settings' })}
            </h3>
            <p style={{ color: 'var(--text-muted)', margin: 0, fontSize: '14px', fontWeight: '500' }}>
              {t('manageApiKeysDescription', { ns: 'settings', defaultValue: 'Manage your API keys and access to the iSmartPay API' })}
            </p>
          </div>
        </div>
      </div>

      <div style={{ padding: '24px' }}>
        {/* App ID Display */}
        {apiKeys.length > 0 && (
          <div className="api-credentials-display" style={{ marginBottom: '24px', padding: '16px', backgroundColor: 'var(--bg-tertiary)', borderRadius: '12px', border: '1px solid var(--border-primary)' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.9rem', color: 'var(--text-primary)' }}>
              <strong>{t('appId', { ns: 'settings', defaultValue: 'App ID' })}:</strong>
              <code style={{
                padding: '6px 12px',
                backgroundColor: 'var(--bg-input)',
                borderRadius: '6px',
                fontFamily: 'monospace',
                fontSize: '0.9rem',
                border: '1px solid var(--border-secondary)',
                color: 'var(--accent)'
              }}>
                {apiKeys[0]?.app_id || t('notAvailableShort', { ns: 'settings', defaultValue: 'N/A' })}
              </code>
              <button
                type="button"
                onClick={() => {
                  if (apiKeys[0]?.app_id) {
                    copyToClipboard(apiKeys[0].app_id, 'app_id');
                  }
                }}
                className="btn-icon"
                style={{ flexShrink: 0 }}
                title={t('copyAppId', { ns: 'settings', defaultValue: 'Copy App ID' })}
              >
                {copiedKey === apiKeys[0]?.app_id ? <Check size={16} /> : <Copy size={16} />}
              </button>

              <div style={{ marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: '8px' }}>
                <span style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>{t('status', { ns: 'settings' })}:</span>
                <span className={`status-value status-${credentialStatus}`} style={{
                  padding: '4px 12px',
                  borderRadius: '20px',
                  fontSize: '0.75rem',
                  fontWeight: '600',
                  textTransform: 'uppercase',
                  backgroundColor: credentialStatus === 'active' ? 'var(--success-bg)' : 'var(--bg-secondary)',
                  color: credentialStatus === 'active' ? 'var(--success)' : 'var(--text-muted)'
                }}>
                  {isLoadingStatus ? <RefreshCw className="animate-spin" size={12} /> : credentialStatus === 'active' ? t('active', { ns: 'settings' }) : t('na', { ns: 'settings' })}
                </span>
                <button
                  type="button"
                  onClick={handleCheckStatus}
                  className="btn-icon"
                  style={{ width: '32px', height: '32px', minWidth: '32px', minHeight: '32px' }}
                  title={t('checkStatus', { ns: 'settings' })}
                >
                  <RefreshCw size={14} />
                </button>
              </div>
            </div>
          </div>
        )}

        {newCredential && (
          <div className="api-section" style={{ backgroundColor: 'var(--success-bg)', border: '1px solid var(--success)', marginBottom: '32px' }} data-tour="settings-api-new-credential">
            <h2 style={{ color: 'var(--success)', borderBottomColor: 'var(--success)', fontSize: '1.25rem' }}>{t('newApiCredential', { ns: 'settings', defaultValue: 'New API Credential' })}</h2>
            <p style={{ color: 'var(--text-primary)', marginBottom: '20px' }}>
              {t('apiSecretVisibleOnce', {
                ns: 'settings',
                defaultValue: 'Your API secret is shown only once. Store it securely now; you will not be able to see it again.'
              })}
            </p>
            <div style={{ display: 'grid', gap: '16px' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                <strong style={{ minWidth: '100px', fontSize: '0.9rem' }}>
                  {t('appId', { ns: 'settings', defaultValue: 'App ID' })}:
                </strong>
                <code style={{
                  flex: 1,
                  padding: '10px 16px',
                  backgroundColor: 'var(--bg-input)',
                  borderRadius: '8px',
                  fontFamily: 'monospace',
                  fontSize: '0.9rem',
                  wordBreak: 'break-all',
                  border: '1px solid var(--border-secondary)',
                  color: 'var(--text-primary)'
                }}>
                  {newCredential.appId}
                </code>
                <button
                  type="button"
                  onClick={() => copyToClipboard(newCredential.appId, 'app_id')}
                  className="btn-icon"
                  title={t('copyAppId', { ns: 'settings' })}
                >
                  {copiedKey === newCredential.appId ? <Check size={18} /> : <Copy size={18} />}
                </button>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                <strong style={{ minWidth: '100px', fontSize: '0.9rem' }}>
                  {t('appSecret', { ns: 'settings', defaultValue: 'App Secret' })}:
                </strong>
                <code style={{
                  flex: 1,
                  padding: '10px 16px',
                  backgroundColor: 'var(--bg-input)',
                  borderRadius: '8px',
                  fontFamily: 'monospace',
                  fontSize: '0.9rem',
                  wordBreak: 'break-all',
                  border: '1px solid var(--border-secondary)',
                  color: 'var(--text-primary)'
                }}>
                  {newCredential.appSecret}
                </code>
                <button
                  type="button"
                  onClick={() => copyToClipboard(newCredential.appSecret, 'secret')}
                  className="btn-icon"
                  title={t('copySecret', { ns: 'settings' })}
                >
                  {copiedKey === newCredential.appSecret ? <Check size={18} /> : <Copy size={18} />}
                </button>
              </div>
            </div>
            <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: '24px' }}>
              <button
                type="button"
                onClick={dismissNewCredential}
                className="btn primary"
                style={{ padding: '10px 24px' }}
              >
                {t('iHaveSavedSecret', { ns: 'settings', defaultValue: 'I have saved this secret' })}
              </button>
            </div>
          </div>
        )}

        {/* Generate New API Key Section */}
        <div className="api-section" data-tour="settings-api-generate">
          <h2 style={{ fontSize: '1.25rem' }}>{t('generateNewApiKey', { ns: 'settings', defaultValue: 'Generate New API Key' })}</h2>

          <div className="alert alert-warning" style={{ borderRadius: '12px', padding: '16px' }}>
            <div className="alert-icon">
              <AlertTriangle size={24} />
            </div>
            <div className="alert-content">
              <h3 style={{ fontSize: '1.1rem', marginBottom: '4px' }}>{t('securityNotice', { ns: 'settings', defaultValue: 'Security Notice' })}</h3>
              <p style={{ fontSize: '0.9rem' }}>{t('keepApiKeysSecure', { ns: 'settings', defaultValue: 'Keep your API keys secure and never share them publicly.' })}</p>
            </div>
          </div>

          <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: '32px' }}>
            <button
              type="button"
              onClick={generateApiKey}
              disabled={generateApiKeyMutation.isPending}
              className="btn primary"
              style={{ minWidth: '200px' }}
              data-tour="settings-api-generate-button"
            >
              {generateApiKeyMutation.isPending ? (
                <>
                  <RefreshCw className="animate-spin" style={{ marginRight: '8px' }} size={18} />
                  {t('generating', { ns: 'settings' })}
                </>
              ) : (
                <>
                  <Key style={{ marginRight: '8px' }} size={18} />
                  {t('generateApiKey', { ns: 'settings' })}
                </>
              )}
            </button>
          </div>
        </div>
      </div>

      {/* Delete Confirmation Modal */}
      {showDeleteConfirm && createPortal(
        <>
          {/* Backdrop */}
          <div
            style={{
              position: 'fixed',
              inset: 0,
              backgroundColor: 'rgba(0, 0, 0, 0.5)',
              backdropFilter: 'blur(4px)',
              zIndex: 10001
            }}
            onClick={cancelDelete}
          />
          {/* Modal */}
          <div
            style={{
              position: 'fixed',
              inset: 0,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              zIndex: 10002,
              pointerEvents: 'none'
            }}
          >
            <div
              style={{
                backgroundColor: 'var(--card, #ffffff)',
                borderRadius: '16px',
                padding: '32px',
                width: '100%',
                maxWidth: '440px',
                boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04)',
                pointerEvents: 'auto',
                margin: '16px',
                animation: 'fadeInScale 0.2s ease-out',
                position: 'relative'
              }}
            >
              {/* Close button */}
              <button
                onClick={cancelDelete}
                style={{
                  position: 'absolute',
                  top: '16px',
                  right: '16px',
                  background: 'transparent',
                  border: 'none',
                  cursor: 'pointer',
                  padding: '8px',
                  borderRadius: '8px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  color: 'var(--text-muted, #6b7280)',
                  transition: 'all 0.2s'
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.backgroundColor = 'var(--bg-hover, #f3f4f6)';
                  e.currentTarget.style.color = 'var(--text-primary, #111827)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.backgroundColor = 'transparent';
                  e.currentTarget.style.color = 'var(--text-muted, #6b7280)';
                }}
              >
                <X size={20} />
              </button>

              {/* Icon */}
              <div style={{
                display: 'flex',
                justifyContent: 'center',
                marginBottom: '24px'
              }}>
                <div style={{
                  width: '64px',
                  height: '64px',
                  borderRadius: '50%',
                  background: 'linear-gradient(135deg, #ef4444 0%, #dc2626 100%)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  boxShadow: '0 4px 12px rgba(239, 68, 68, 0.3)'
                }}>
                  <Trash2 size={32} color="white" />
                </div>
              </div>

              {/* Title */}
              <h3 style={{
                fontSize: '20px',
                fontWeight: '600',
                color: 'var(--text-primary, #111827)',
                textAlign: 'center',
                marginBottom: '12px'
              }}>
                {t('removeApiKey', { ns: 'settings', defaultValue: 'Remove API Key?' })}
              </h3>

              {/* Message */}
              <p style={{
                fontSize: '14px',
                color: 'var(--text-secondary, #6b7280)',
                textAlign: 'center',
                lineHeight: '1.5',
                marginBottom: '32px'
              }}>
                {t('removeKeyFromDisplayConfirm', {
                  ns: 'settings',
                  defaultValue: 'Are you sure you want to remove the API key ? '
                })}
              </p>

              {/* Buttons */}
              <div style={{
                display: 'flex',
                gap: '12px',
                justifyContent: 'flex-end'
              }}>
                <button
                  onClick={cancelDelete}
                  style={{
                    padding: '10px 20px',
                    borderRadius: '8px',
                    border: '1px solid var(--border-secondary, #e5e7eb)',
                    backgroundColor: 'transparent',
                    color: 'var(--text-primary, #111827)',
                    fontSize: '14px',
                    fontWeight: '500',
                    cursor: 'pointer',
                    transition: 'all 0.2s'
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = 'var(--bg-hover, #f3f4f6)';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = 'transparent';
                  }}
                >
                  {t('cancel', { ns: 'settings', defaultValue: 'Cancel' })}
                </button>
                <button
                  onClick={confirmDelete}
                  style={{
                    padding: '10px 20px',
                    borderRadius: '8px',
                    border: 'none',
                    backgroundColor: '#ef4444',
                    color: 'white',
                    fontSize: '14px',
                    fontWeight: '500',
                    cursor: 'pointer',
                    transition: 'all 0.2s',
                    boxShadow: '0 1px 2px 0 rgba(0, 0, 0, 0.05)'
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = '#dc2626';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = '#ef4444';
                  }}
                >
                  {t('remove', { ns: 'settings', defaultValue: 'Remove' })}
                </button>
              </div>
            </div>
          </div>
        </>,
        document.body
      )}
    </div>
  );
};

export default API;
