/**
 * Custom Hook for Bank Account Management
 * 
 * Handles loading, adding, and managing business bank accounts.
 */

import { useState, useEffect, useCallback } from 'react';
import { businessAccountsService } from '@/features/settings/services';
import { tokenService } from '@/features/auth/services';
import { logger } from '@/shared/utils/logger.js';
import { useQuery, useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';

export const useBankAccounts = (businessType, tradingName) => {
  const [isAddingBankAccount, setIsAddingBankAccount] = useState(false);
  const [newBankAccount, setNewBankAccount] = useState({
    bankName: '',
    accountNumber: '',
    accountType: 'current',
    accountHolderName: '',
    openedDate: '',
    swiftCode: '',
    phone: '',
    phoneCountryCode: '233', // Default to Ghana
  });

  /**
   * Get business ID
   */
  const getBusinessId = useCallback(async () => {
    try {
      const userData = JSON.parse(localStorage.getItem('userData') || '{}');
      const storedBusinessId = localStorage.getItem('businessId');

      if (storedBusinessId) {return storedBusinessId;}
      if (userData?.businesses?.[0]?.id || userData?.business?.id || userData?.business_id || userData?.businessId) {
        const businessId = userData.businesses?.[0]?.id || userData.business?.id || userData.business_id || userData.businessId;
        localStorage.setItem('businessId', businessId);
        return businessId;
      }
      return null;
    } catch (error) {
      logger.error('Error getting business ID', { error });
      return null;
    }
  }, []);

  // Get business ID state for useQuery
  const [businessId, setBusinessId] = useState(null);

  // Load business ID on mount
  useEffect(() => {
    getBusinessId().then(id => {
      if (id) {
        setBusinessId(id);
      }
    });
  }, [getBusinessId]);

  // Use React Query to fetch bank accounts with proper endpoint
  // GET /auth/business/{businessId}/accounts (base URL already includes /api)
  const { data: accountsResponse, isLoading: isLoadingAccounts, refetch: refetchAccounts } = useQuery({
    queryKey: [...queryKeys.settings.bankAccounts(), businessId], // Include businessId for cache isolation
    endpoint: `/auth/business/${businessId}/accounts`,
    enabled: !!businessId, // Only fetch when businessId is available
    staleTime: 2 * 60 * 1000, // 2 minutes
    refetchOnWindowFocus: false, // Reduced from true to prevent excessive refetches
    select: (response) => {
      // Handle different response formats
      let allAccounts = [];
      
      if (response?.data) {
        allAccounts = Array.isArray(response.data) ? response.data : (Array.isArray(response.data.accounts) ? response.data.accounts : []);
      } else if (Array.isArray(response)) {
        allAccounts = response;
      } else if (response?.accounts && Array.isArray(response.accounts)) {
        allAccounts = response.accounts;
      }
      
      // Filter to only return bank accounts (not mobile money accounts)
      const bankAccounts = allAccounts.filter(account => 
        account.account_type === 'bank' || 
        account.accountType === 'bank' ||
        (!account.account_type && !account.accountType) // If no type specified, assume it's a bank account
      );
      
      // Normalize field names to camelCase for consistent access
      return bankAccounts.map(account => ({
        id: account.id,
        bankName: account.bankName || account.bank_name,
        accountNumber: account.accountNumber || account.account_number,
        accountType: account.accountType || account.account_type || account.account_category || 'current',
        accountHolderName: account.accountHolderName || account.account_holder_name,
        openedDate: account.openedDate || account.opened_date,
        swiftCode: account.swiftCode || account.swift_bic || account.swift_code,
        branch: account.branch,
        phone: account.phone || null,
        accountCurrency: account.accountCurrency || account.account_currency || null,
        sortCode: account.sortCode || account.sort_code || null,
        createdAt: account.createdAt || account.created_at || null,
        isVerified: account.isVerified !== undefined ? account.isVerified : (account.is_verified !== undefined ? account.is_verified : false),
        verified: account.verified !== undefined ? account.verified : account.isVerified !== undefined ? account.isVerified : false,
        // Keep original data for any other fields
        ...account
      }));
    },
    onError: (error) => {
      logger.error('Error loading bank accounts', { error });
    },
  });

  const bankAccounts = accountsResponse || [];

  // Use React Query mutation for adding bank account
  const addBankAccountMutation = useMutation({
    mutationFn: async ({ businessId: bizId, accountData }) => {
      return await businessAccountsService.addBankAccount(bizId, accountData);
    },
    invalidateQueries: [
      [...queryKeys.settings.bankAccounts(), businessId], // Include businessId in invalidation
      queryKeys.settings.all(),
    ],
    onSuccess: () => {
      logger.info('Bank account added successfully');
      setNewBankAccount({
        bankName: '',
        accountNumber: '',
        accountType: 'current',
        accountHolderName: '',
        openedDate: '',
        swiftCode: '',
        phone: '',
        phoneCountryCode: '233',
      });
      setIsAddingBankAccount(false);
    },
    onError: (error) => {
      logger.error('Error adding bank account', { error });
      throw error;
    },
  });

  // Use React Query mutation for deleting bank account
  const deleteBankAccountMutation = useMutation({
    mutationFn: async ({ businessId: bizId, accountId }) => {
      return await businessAccountsService.deleteBankAccount(bizId, accountId);
    },
    invalidateQueries: [
      [...queryKeys.settings.bankAccounts(), businessId], // Include businessId in invalidation
      queryKeys.settings.all(),
    ],
    onSuccess: () => {
      logger.info('Bank account deleted successfully');
    },
    onError: (error) => {
      logger.error('Error deleting bank account', { error });
      throw error;
    },
  });

  /**
   * Add bank account
   */
  const addBankAccount = useCallback(async () => {
    // Resolve holder name from user data if not provided
    let resolvedHolderName = newBankAccount.accountHolderName;
    if (!resolvedHolderName) {
      try {
        const user = tokenService.getUserData();
        resolvedHolderName = user?.trading_name || user?.business_name || tradingName || '';
      } catch (e) {
        logger.error('Error resolving account holder name', { error: e });
      }
    }

    // Validate required fields
    if (!newBankAccount.bankName || !newBankAccount.accountNumber || !resolvedHolderName) {
      throw new Error('Please fill in Bank Name, Account Number, and Account Holder Name');
    }

    // Additional validation for Corporate business type
    if (businessType !== 'Starter') {
      if (!newBankAccount.accountType) {
        throw new Error('Account Type is required for Corporate business accounts');
      }
    }

    // Use the businessId from state, or fetch it if not available
    const bizId = businessId || await getBusinessId();
    if (!bizId) {
      throw new Error('Business ID not found');
    }

    // Format date to ISO format if provided
    const formatDateToISO = (dateString) => {
      if (!dateString) {return undefined;}
      // If it's already in ISO format, return as is
      if (dateString.includes('T')) {return dateString;}
      // Convert YYYY-MM-DD to ISO format
      try {
        const date = new Date(dateString + 'T00:00:00.000Z');
        if (isNaN(date.getTime())) {return undefined;}
        try {
          return date.toISOString();
        } catch (e) {
          logger.warn('Failed to convert date to ISO string', { dateString, error: e });
          return undefined;
        }
      } catch (e) {
        logger.warn('Invalid date format for openedDate', { dateString, error: e });
        return undefined;
      }
    };

    // Format phone number: combine country code and phone number
    let formattedPhone = null;
    if (newBankAccount.phone && newBankAccount.phone.trim()) {
      const phoneNumber = newBankAccount.phone.replace(/^0+/, '').replace(/[^\d]/g, '');
      const countryCode = newBankAccount.phoneCountryCode || '233';
      if (phoneNumber.length >= 7 && phoneNumber.length <= 15) {
        formattedPhone = countryCode + phoneNumber;
      }
    }

    const accountData = {
      bankName: newBankAccount.bankName,
      accountNumber: newBankAccount.accountNumber,
      accountType: newBankAccount.accountType,
      accountHolderName: resolvedHolderName,
      openedDate: formatDateToISO(newBankAccount.openedDate),
      swiftCode: newBankAccount.swiftCode || null,
      phone: formattedPhone,
    };

    logger.debug('Adding bank account', { businessId: bizId, accountData });
    addBankAccountMutation.mutate({ businessId: bizId, accountData });
    return true;
  }, [newBankAccount, businessType, tradingName, businessId, getBusinessId, addBankAccountMutation]);

  /**
   * Delete bank account
   */
  const deleteBankAccount = useCallback(async (accountId) => {
    // Use the businessId from state, or fetch it if not available
    const bizId = businessId || await getBusinessId();
    if (!bizId) {
      throw new Error('Business ID not found');
    }

    logger.debug('Deleting bank account', { businessId: bizId, accountId });
    deleteBankAccountMutation.mutate({ businessId: bizId, accountId });
    return true;
  }, [businessId, getBusinessId, deleteBankAccountMutation]);

  return {
    bankAccounts,
    isLoadingAccounts,
    isAddingBankAccount,
    setIsAddingBankAccount,
    newBankAccount,
    setNewBankAccount,
    addBankAccount,
    deleteBankAccount,
    reload: refetchAccounts
  };
};

