/**
 * Custom Hook for Business Owner Management
 * 
 * Handles adding business owners with KYC information.
 */

import { useState, useCallback, useEffect } from 'react';
import { businessService } from '@/features/settings/services';
import { logger } from '@/shared/utils/logger.js';
import { useMutation, useQuery } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';

export const useBusinessOwners = () => {
  const [isAddingOwner, setIsAddingOwner] = useState(false);
  const [businessId, setBusinessId] = useState(null);
  const [newOwner, setNewOwner] = useState({
    full_name: '',
    place_of_birth: '',
    nationality: '',
    country_of_residence: '',
    occupation: '',
    position: '',
    ownership_percentage: '',
    id_type: '',
    id_number: '',
    id_issue_date: '',
    id_expiry_date: '',
    id_issuing_authority: '',
    residential_address: '',
    dob: '',
  });

  /**
   * Get business ID
   */
  const getBusinessId = useCallback(async () => {
    try {
      const userData = JSON.parse(localStorage.getItem('userData') || '{}');
      const storedBusinessId = localStorage.getItem('businessId');

      if (storedBusinessId) {
        setBusinessId(storedBusinessId);
        return storedBusinessId;
      }
      if (userData?.businesses?.[0]?.id || userData?.business?.id || userData?.business_id || userData?.businessId) {
        const id = userData.businesses?.[0]?.id || userData.business?.id || userData.business_id || userData.businessId;
        localStorage.setItem('businessId', id);
        setBusinessId(id);
        return id;
      }
      return null;
    } catch (error) {
      logger.error('Error getting business ID', { error });
      return null;
    }
  }, []);

  // Load business ID on mount
  useEffect(() => {
    getBusinessId().then(id => {
      if (id) {
        setBusinessId(id);
      }
    });
  }, [getBusinessId]);

  // Use React Query to fetch business owners with proper endpoint
  const { data: ownersResponse, isLoading: isLoadingOwners, refetch: refetchOwners } = useQuery({
    queryKey: [...queryKeys.settings.businessOwners(), businessId], // Include businessId for cache isolation
    queryFn: async () => {
      try {
        const response = await businessService.getBusinessOwners(businessId);
        return response;
      } catch (error) {
        // Handle specific backend errors gracefully
        if (error?.message?.includes('toISOString') ||
          error?.message?.includes('dob') ||
          error?.code === '07' ||
          (error?.data?.message && error.data.message.includes('toISOString'))) {
          logger.warn('Backend error processing owner date fields. This may indicate invalid data in the database. Returning empty array to prevent UI errors.', { error });
          return [];
        }
        // Re-throw other errors
        throw error;
      }
    },
    enabled: !!businessId, // Only fetch when businessId is available
    staleTime: 2 * 60 * 1000, // 2 minutes
    refetchOnWindowFocus: false, // Reduced from true to prevent excessive refetches
    select: (response) => {
      // If we already returned [] from catch block, it will be handled here
      if (!response || !Array.isArray(response) && response.length === 0) {
        return [];
      }

      try {
        // The businessService.getBusinessOwners already returns a sanitized array
        // but we double check here just in case
        let owners = [];

        if (Array.isArray(response)) {
          owners = response;
        } else if (response?.data) {
          owners = Array.isArray(response.data) ? response.data : (Array.isArray(response.data.owners) ? response.data.owners : []);
        } else if (response?.owners && Array.isArray(response.owners)) {
          owners = response.owners;
        }

        return owners.filter(owner => owner !== null);
      } catch (error) {
        logger.error('Error in select transformer for business owners', { error });
        return [];
      }
    },
    // Return empty array as default value
    retry: false, // Don't retry on errors to avoid repeated backend errors
  });

  const businessOwners = ownersResponse || [];

  // Use React Query mutation for adding business owner
  const addBusinessOwnerMutation = useMutation({
    mutationFn: async ({ businessId, formattedOwner }) => {
      return await businessService.addBusinessOwner(businessId, formattedOwner);
    },
    invalidateQueries: [
      queryKeys.settings.business(),
      queryKeys.settings.businessOwners(businessId),
      queryKeys.settings.all(),
    ],
    onSuccess: () => {
      logger.info('Business owner added successfully');
      setNewOwner({
        full_name: '',
        place_of_birth: '',
        nationality: '',
        country_of_residence: '',
        occupation: '',
        position: '',
        ownership_percentage: '',
        id_type: '',
        id_number: '',
        id_issue_date: '',
        id_expiry_date: '',
        id_issuing_authority: '',
        residential_address: '',
        dob: '',
      });
      setIsAddingOwner(false);
    },
    onError: (error) => {
      logger.error('Error adding business owner', { error });
      throw error;
    },
  });

  /**
   * Add business owner
   */
  const addBusinessOwner = useCallback(async () => {
    // Validate required fields
    if (!newOwner.full_name) {
      throw new Error('Full name is required');
    }

    const businessId = await getBusinessId();
    if (!businessId) {
      throw new Error('Business ID not found');
    }

    // Format the data properly
    // Convert date strings to ISO format (Date objects will be serialized to ISO strings by JSON.stringify)
    const formatDateToISO = (dateString) => {
      if (!dateString || (typeof dateString === 'string' && dateString.trim() === '')) {
        return null; // Return null for empty values
      }

      // If it's already in ISO format, validate it
      if (typeof dateString === 'string' && dateString.includes('T')) {
        try {
          const testDate = new Date(dateString);
          if (!isNaN(testDate.getTime())) {
            // Valid ISO string, return as is
            return dateString;
          }
        } catch (e) {
          logger.warn('Invalid ISO date string', { dateString, error: e });
          return null;
        }
      }

      // Convert YYYY-MM-DD to ISO format
      if (typeof dateString === 'string') {
        try {
          // Ensure it's in YYYY-MM-DD format
          const dateMatch = dateString.match(/^(\d{4})-(\d{2})-(\d{2})/);
          if (!dateMatch) {
            logger.warn('Date string not in YYYY-MM-DD format', { dateString });
            return null;
          }

          const date = new Date(dateString + 'T00:00:00.000Z');
          if (isNaN(date.getTime())) {
            logger.warn('Invalid date value', { dateString });
            return null;
          }
          try {
            return date.toISOString();
          } catch (e) {
            logger.warn('Failed to convert date to ISO string', { dateString, error: e });
            return null;
          }
        } catch (e) {
          logger.warn('Error formatting date', { dateString, error: e });
          return null;
        }
      }

      // If it's a Date object, convert to ISO string
      if (dateString instanceof Date) {
        if (isNaN(dateString.getTime())) {
          return null;
        }
        try {
          return dateString.toISOString();
        } catch (e) {
          logger.warn('Failed to convert Date object to ISO string', { dateString, error: e });
          return null;
        }
      }

      return null;
    };

    // Build formatted owner, only including fields that have values
    const formattedOwner = {
      full_name: newOwner.full_name,
    };

    // Add optional fields only if they have values
    if (newOwner.place_of_birth?.trim()) { formattedOwner.place_of_birth = newOwner.place_of_birth.trim(); }
    if (newOwner.nationality?.trim()) { formattedOwner.nationality = newOwner.nationality.trim(); }
    if (newOwner.country_of_residence?.trim()) { formattedOwner.country_of_residence = newOwner.country_of_residence.trim(); }
    if (newOwner.occupation?.trim()) { formattedOwner.occupation = newOwner.occupation.trim(); }
    if (newOwner.position?.trim()) { formattedOwner.position = newOwner.position.trim(); }
    if (newOwner.ownership_percentage) { formattedOwner.ownership_percentage = parseFloat(newOwner.ownership_percentage); }
    if (newOwner.id_type?.trim()) { formattedOwner.id_type = newOwner.id_type.trim(); }
    if (newOwner.id_number?.trim()) { formattedOwner.id_number = newOwner.id_number.trim(); }
    if (newOwner.id_issuing_authority?.trim()) { formattedOwner.id_issuing_authority = newOwner.id_issuing_authority.trim(); }
    if (newOwner.residential_address?.trim()) { formattedOwner.residential_address = newOwner.residential_address.trim(); }

    // Only add date fields if they're valid and formatted
    const formattedDob = formatDateToISO(newOwner.dob);
    if (formattedDob) { formattedOwner.dob = formattedDob; }

    const formattedIdIssueDate = formatDateToISO(newOwner.id_issue_date);
    if (formattedIdIssueDate) { formattedOwner.id_issue_date = formattedIdIssueDate; }

    const formattedIdExpiryDate = formatDateToISO(newOwner.id_expiry_date);
    if (formattedIdExpiryDate) { formattedOwner.id_expiry_date = formattedIdExpiryDate; }

    logger.debug('Adding business owner', { businessId, owner: formattedOwner });
    return await addBusinessOwnerMutation.mutateAsync({ businessId, formattedOwner });
  }, [newOwner, getBusinessId, addBusinessOwnerMutation]);

  /**
   * Cancel adding owner
   */
  const cancelAddOwner = useCallback(() => {
    setNewOwner({
      full_name: '',
      place_of_birth: '',
      nationality: '',
      country_of_residence: '',
      occupation: '',
      position: '',
      ownership_percentage: '',
      id_type: '',
      id_number: '',
      id_issue_date: '',
      id_expiry_date: '',
      id_issuing_authority: '',
      residential_address: '',
      dob: '',
    });
    setIsAddingOwner(false);
  }, []);

  // Use React Query mutation for deleting business owner
  const deleteBusinessOwnerMutation = useMutation({
    mutationFn: async ({ businessId, ownerId }) => {
      return await businessService.deleteBusinessOwner(businessId, ownerId);
    },
    invalidateQueries: [
      queryKeys.settings.business(),
      queryKeys.settings.businessOwners(businessId),
      queryKeys.settings.all(),
    ],
    onSuccess: () => {
      logger.info('Business owner deleted successfully');
    },
    onError: (error) => {
      logger.error('Error deleting business owner', { error });
      throw error;
    },
  });

  const deleteBusinessOwner = useCallback(async (ownerId) => {
    const businessId = await getBusinessId();
    if (!businessId) {
      throw new Error('Business ID not found');
    }
    if (!ownerId) {
      throw new Error('Owner ID is required');
    }

    logger.debug('Deleting business owner', { businessId, ownerId });
    return await deleteBusinessOwnerMutation.mutateAsync({ businessId, ownerId });
  }, [getBusinessId, deleteBusinessOwnerMutation]);

  return {
    businessOwners,
    isLoadingOwners,
    isAddingOwner,
    setIsAddingOwner,
    newOwner,
    setNewOwner,
    addBusinessOwner,
    cancelAddOwner,
    deleteBusinessOwner,
    isDeletingOwner: deleteBusinessOwnerMutation.isLoading,
    reload: refetchOwners
  };
};

