/**
 * Team Management Settings Page
 * 
 * Manages team creation, member addition, and access control for business
 * accounts. Handles team hierarchy, page access permissions, and team
 * member management operations.
 */

import React, { useState, useEffect, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { teamService } from '@/features/settings/services';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { usePermissions } from '@/app/providers/PermissionsContext.jsx';
import TeamCreationModal from '@/features/settings/components/TeamCreationModal.jsx';
import AddTeamMemberModal from '@/features/settings/components/AddTeamMemberModal.jsx';
import TeamMemberList from '@/features/settings/components/TeamMemberList.jsx';

import { tokenService } from '@/features/auth/services/tokenService.js';
import { useMutation, useQuery } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import logger from '@/shared/utils/logger.js';

const Team = () => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const { refreshPermissions } = usePermissions();

  const [selectedTeam, setSelectedTeam] = useState(null);
  const [isCreatingTeam, setIsCreatingTeam] = useState(false);
  const [isAddingMember, setIsAddingMember] = useState(false);
  const [showTeamModal, setShowTeamModal] = useState(false);
  const [teamToEdit, setTeamToEdit] = useState(null);
  const [showMemberModal, setShowMemberModal] = useState(false);
  const [businessId, setBusinessId] = useState(null);
  const [userData, setUserData] = useState(null);
  const [windowWidth, setWindowWidth] = useState(typeof window !== 'undefined' ? window.innerWidth : 1024);

  const isMobile = windowWidth <= 768;
  const isTablet = windowWidth > 768 && windowWidth <= 1024;

  // Handle window resize for responsive design
  useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      // Debounce resize events to prevent excessive re-renders
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
      resizeTimer = setTimeout(() => {
        setWindowWidth(window.innerWidth);
      }, 100);
    };
    
    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
    };
  }, []);

  // Team details are already available from the teams list query (teamsDataRaw)
  // No need for a separate API call when selecting a team - all data is in the initial response

  // Load business ID on mount
  useEffect(() => {
    const loadBusinessId = async () => {
      try {
        const user = tokenService.getUserData();
        setUserData(user);

        const businessIdToUse = await getBusinessId();

        if (!businessIdToUse) {
          showError(t('businessIdNotFoundLogin', { ns: 'settings', defaultValue: 'Business ID not found. Please ensure you are logged in.' }));
          return;
        }

        logger.debug('Team: Business ID loaded', { businessId: businessIdToUse });
        setBusinessId(businessIdToUse);
      } catch (error) {
        logger.error('Team: Error loading business ID', { error });
        showError(t('errorLoadingBusinessId', { ns: 'settings', defaultValue: 'Error loading business information. Please try again.' }));
      }
    };
    loadBusinessId();
  }, []);

  // Helper function to get business ID with fallback logic
  const getBusinessId = async () => {
    try {
      // First try localStorage - look for business-specific ID from businesses array
      const userData = JSON.parse(localStorage.getItem('userData') || '{}');
      logger.debug('Team: Current userData from localStorage', { userData });

      const businessId = userData.businesses?.[0]?.id || userData.business?.id || userData.business_id || userData.businessId;
      logger.debug('Team: Extracted business ID from localStorage', { businessId });

      if (businessId) {
        logger.debug('Team: Validating business ID format');
        // Validate business ID format (UUID)
        const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
        if (!uuidRegex.test(businessId)) {
          logger.debug('Team: Business ID format invalid, fetching fresh profile data');
        } else {
          logger.debug('Team: Business ID format valid, using', { businessId });
          return businessId;
        }
      }

      // Fallback: try to fetch fresh profile data
      logger.debug('Team: Business ID not found or invalid in localStorage, trying to fetch fresh profile data');
      const { profileService } = await import('@/features/settings/services');
      const profileData = await profileService.getUserProfile();
      logger.debug('Team: Fresh profile data received', { profileData });

      if (profileData?.businesses?.[0]?.id || profileData?.business?.id || profileData?.business_id || profileData?.businessId) {
        const freshBusinessId = profileData.businesses?.[0]?.id || profileData.business?.id || profileData.business_id || profileData.businessId;
        logger.debug('Team: Found business ID in fresh profile data', { freshBusinessId });

        // Update localStorage with fresh data
        const currentUserData = JSON.parse(localStorage.getItem('userData') || '{}');
        // Preserve the original login user ID - don't let profile data overwrite it
        const preservedId = currentUserData.id;
        const { id: profileId, ...profileDataWithoutId } = profileData;
        const updatedUserData = {
          ...currentUserData,
          ...profileDataWithoutId,
          id: preservedId // Always preserve the login user ID
        };
        localStorage.setItem('userData', JSON.stringify(updatedUserData));

        return freshBusinessId;
      }

      // Check if user is a business user
      logger.debug('Team: No business ID found', { userType: profileData?.usertype || userData?.usertype });
      if (profileData?.usertype === 'business' || userData?.usertype === 'business') {
        logger.warn('Team: User is a business user but no business ID found. This may indicate a data inconsistency');
      }

      return null;
    } catch (error) {
      logger.error('Team: Error getting business ID', { error });
      return null;
    }
  };


  // State to track member counts for each team
  const [teamMemberCounts, setTeamMemberCounts] = useState({});

  // Use React Query to load teams with automatic caching and refetching
  const { data: teamsDataRaw, isLoading: loading } = useQuery({
    queryKey: queryKeys.settings.team(),
    endpoint: '/team/' + businessId,
    enabled: !!businessId,
    staleTime: 5 * 60 * 1000, // 5 minutes - teams don't change frequently
    cacheTime: 10 * 60 * 1000, // 10 minutes
    refetchOnWindowFocus: false, // Reduced from true to prevent excessive refetches
    select: (response) => {
      // Handle different response structures
      const teamsData = response?.data || response || [];
      if (Array.isArray(teamsData)) {
        return teamsData.map(team => ({
          ...team,
          page_access: team.menus || [], // Convert menus to page_access for UI consistency
          status: 'active', // Default status
        }));
      }
      return [];
    },
    onError: (error) => {
      logger.error('Failed to load teams', { error });
      showError(error?.message || t('failedToLoadTeams', { ns: 'settings', defaultValue: 'Failed to load teams' }));
    },
  });

  // Fetch member counts for all teams
  useEffect(() => {
    if (!teamsDataRaw || !Array.isArray(teamsDataRaw) || teamsDataRaw.length === 0) {return;}

    const fetchMemberCounts = async () => {
      const counts = {};
      await Promise.all(
        teamsDataRaw.map(async (team) => {
          try {
            const membersResponse = await teamService.getTeamMembers(team.id);
            const members = membersResponse?.data || (Array.isArray(membersResponse) ? membersResponse : []);
            counts[team.id] = Array.isArray(members) ? members.length : 0;
          } catch (error) {
            logger.error('Failed to fetch members for team', { error, teamId: team.id });
            counts[team.id] = team.members?.length || 0;
          }
        })
      );
      setTeamMemberCounts(prev => ({ ...prev, ...counts }));
    };

    fetchMemberCounts();
  }, [teamsDataRaw]);

  // Combine teams data with member counts
  const teams = useMemo(() => {
    if (!teamsDataRaw || !Array.isArray(teamsDataRaw)) {return [];}
    return teamsDataRaw.map(team => ({
      ...team,
      member_count: teamMemberCounts[team.id] ?? team.members?.length ?? 0
    }));
  }, [teamsDataRaw, teamMemberCounts]);



  const handleCreateTeam = async (createdTeam) => {
    // React Query automatically invalidates cache via mutation, no manual refetch needed
    // Refresh user permissions to reflect the changes
    refreshPermissions();
  };

  const handleTeamUpdated = (updatedTeam) => {
    // React Query automatically invalidates cache via mutation, no manual refetch needed
    refreshPermissions();
    if (selectedTeam && selectedTeam.id === updatedTeam.id) {
      setSelectedTeam(prev => ({ ...prev, ...updatedTeam }));
    }
  };



  const handleMemberAdded = (newMember) => {
    // Update member count for the selected team
    if (selectedTeam) {
      setTeamMemberCounts(prev => ({
        ...prev,
        [selectedTeam.id]: (prev[selectedTeam.id] || 0) + 1
      }));
    }
    // React Query automatically invalidates cache via mutation, no manual refetch needed
  };

  const handleMemberRemoved = () => {
    // Update member count for the selected team
    if (selectedTeam) {
      setTeamMemberCounts(prev => ({
        ...prev,
        [selectedTeam.id]: Math.max(0, (prev[selectedTeam.id] || 0) - 1)
      }));
    }
    // React Query automatically invalidates cache via mutation, no manual refetch needed
  };


  const availablePages = useMemo(() => [
    { id: 'collections', name: t('collections', { ns: 'common' }), description: t('pageDescriptionCollections', { ns: 'settings' }) },
    { id: 'disbursements', name: t('disbursements', { ns: 'common' }), description: t('pageDescriptionDisbursements', { ns: 'settings' }) },
    { id: 'invoicing', name: t('invoicing', { ns: 'common' }), description: t('pageDescriptionInvoicing', { ns: 'settings' }) },
    { id: 'payroll', name: t('payroll', { ns: 'common' }), description: t('pageDescriptionPayroll', { ns: 'settings' }) },
    { id: 'reports', name: t('reports', { ns: 'common' }), description: t('pageDescriptionReports', { ns: 'settings' }) },
    { id: 'payment_methods', name: t('paymentMethods', { ns: 'settings' }), description: t('pageDescriptionPaymentMethods', { ns: 'settings' }) },
    { id: 'business_profile', name: t('businessProfile', { ns: 'settings' }), description: t('pageDescriptionBusinessProfile', { ns: 'settings' }) },
    { id: 'security', name: t('security', { ns: 'settings' }), description: t('pageDescriptionSecurity', { ns: 'settings' }) },
    { id: 'team_management', name: t('teamManagement', { ns: 'settings' }), description: t('pageDescriptionTeamManagement', { ns: 'settings' }) },
    { id: 'api_settings', name: t('apiManagement', { ns: 'settings' }), description: t('pageDescriptionApiSettings', { ns: 'settings' }) },
    { id: 'utilities', name: t('utilities', { ns: 'common' }), description: t('pageDescriptionUtilities', { ns: 'settings' }) }
  ], [t]);

  return (
    <div className="invoices-card">
      <div className="card-head">
        <div style={{ 
          display: 'flex', 
          alignItems: 'center', 
          gap: '16px',
          padding: '8px 0'
        }}>
          <div style={{
            width: '56px',
            height: '56px',
            borderRadius: '14px',
            background: 'linear-gradient(135deg, var(--accent) 0%, var(--accent-hover) 100%)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            boxShadow: 'var(--shadow-md)'
          }}>
            <span className="material-symbols-outlined" style={{ 
              fontSize: '32px', 
              color: 'white' 
            }}>
              groups
            </span>
          </div>
          <div>
            <h3 style={{ 
              margin: 0, 
              fontSize: '24px',
              fontWeight: '700',
              color: 'var(--text-primary)',
              marginBottom: '4px'
            }}>{t('teamManagement', { ns: 'settings' })}</h3>
            <p style={{ 
              color: 'var(--text-muted)', 
              margin: 0,
              fontSize: '14px',
              fontWeight: '500'
            }}>{t('teamManagementDescription', { ns: 'settings', defaultValue: 'Invite and manage team members with specific page access permissions.' })}</p>
          </div>
        </div>
      </div>

      <div style={{ padding: '32px 24px' }}>
        {/* Teams Overview */}
        <div data-tour="settings-team-overview" style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: '32px',
          padding: '24px',
          backgroundColor: 'var(--bg-tertiary)',
          borderRadius: '16px',
          border: '1px solid var(--border-primary)'
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <span className="material-symbols-outlined" style={{ fontSize: '24px', color: 'var(--accent)' }}>
              group
            </span>
            <div>
              <h4 style={{
                margin: 0,
                fontSize: '16px',
                fontWeight: '600',
                color: 'var(--text-primary)'
              }}>
                {t('teams', { ns: 'settings', defaultValue: 'Teams' })} ({teams.length})
              </h4>
              <p style={{
                margin: '4px 0 0 0',
                fontSize: '13px',
                color: 'var(--text-muted)'
              }}>
                {t('manageTeamsPermissions', { ns: 'settings', defaultValue: 'Manage your teams and their access permissions' })}
              </p>
            </div>
          </div>
          <button
            onClick={() => {
              setTeamToEdit(null);
              setShowTeamModal(true);
            }}
            data-tour="settings-team-create-button"
            style={{
              padding: '10px 20px',
              backgroundColor: 'var(--accent)',
              color: 'var(--text-inverse)',
              border: 'none',
              borderRadius: 'var(--radius-md)',
              fontSize: '14px',
              fontWeight: '600',
              cursor: 'pointer',
              display: 'inline-flex',
              alignItems: 'center',
              gap: '8px',
              transition: 'all var(--transition-base)',
              boxShadow: 'var(--shadow-sm)'
            }}
            onMouseEnter={(e) => {
              e.target.style.backgroundColor = 'var(--accent-hover)';
              e.target.style.boxShadow = 'var(--shadow-md)';
              e.target.style.transform = 'translateY(-1px)';
            }}
            onMouseLeave={(e) => {
              e.target.style.backgroundColor = 'var(--accent)';
              e.target.style.boxShadow = 'var(--shadow-sm)';
              e.target.style.transform = 'translateY(0)';
            }}
          >
            <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>add</span>
            {t('createTeam', { ns: 'settings', defaultValue: 'Create Team' })}
          </button>
        </div>

        {/* Teams List */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: isMobile ? '1fr' : 'repeat(auto-fill, minmax(380px, 1fr))',
          gap: '24px',
          marginBottom: '32px'
        }}>
          {teams.map((team) => (
            <div
              key={team.id}
              style={{
                border: selectedTeam?.id === team.id ? '2px solid var(--accent)' : '2px solid var(--border-primary)',
                borderRadius: 'var(--radius-lg)',
                overflow: 'hidden',
                backgroundColor: selectedTeam?.id === team.id ? 'var(--info-bg)' : 'var(--card)',
                cursor: 'pointer',
                transition: 'all var(--transition-base)',
                boxShadow: selectedTeam?.id === team.id ? 'var(--shadow-lg)' : 'var(--shadow-sm)',
                position: 'relative',
                transform: selectedTeam?.id === team.id ? 'scale(1.02)' : 'scale(1)'
              }}
              onClick={() => setSelectedTeam(team)}
              onMouseEnter={(e) => {
                if (selectedTeam?.id !== team.id) {
                  e.currentTarget.style.borderColor = 'var(--accent)';
                  e.currentTarget.style.backgroundColor = 'var(--bg-hover)';
                  e.currentTarget.style.transform = 'scale(1.01)';
                  e.currentTarget.style.boxShadow = 'var(--shadow-md)';
                }
              }}
              onMouseLeave={(e) => {
                if (selectedTeam?.id !== team.id) {
                  e.currentTarget.style.borderColor = 'var(--border-primary)';
                  e.currentTarget.style.backgroundColor = 'var(--card)';
                  e.currentTarget.style.transform = 'scale(1)';
                  e.currentTarget.style.boxShadow = 'var(--shadow-sm)';
                }
              }}
            >
              <div style={{
                padding: '24px',
                borderBottom: '2px solid var(--border-primary)',
                background: selectedTeam?.id === team.id 
                  ? 'linear-gradient(135deg, var(--info-bg) 0%, var(--bg-tertiary) 100%)'
                  : 'linear-gradient(135deg, var(--card) 0%, var(--bg-tertiary) 100%)'
              }}>
                <div style={{
                  display: 'flex',
                  alignItems: 'flex-start',
                  justifyContent: 'space-between',
                  marginBottom: '12px'
                }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '10px', flex: 1 }}>
                    <div style={{
                      width: '48px',
                      height: '48px',
                      borderRadius: '12px',
                      background: selectedTeam?.id === team.id 
                        ? 'linear-gradient(135deg, var(--accent) 0%, var(--accent-hover) 100%)'
                        : 'linear-gradient(135deg, var(--bg-secondary) 0%, var(--bg-tertiary) 100%)',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      boxShadow: 'var(--shadow-sm)'
                    }}>
                      <span className="material-symbols-outlined" style={{
                        fontSize: '24px',
                        color: selectedTeam?.id === team.id ? 'white' : 'var(--accent)'
                      }}>
                        group
                      </span>
                    </div>
                    <div style={{ flex: 1 }}>
                      <h5 style={{
                        margin: 0,
                        fontSize: '18px',
                        fontWeight: '700',
                        color: 'var(--text-primary)',
                        marginBottom: '4px'
                      }}>
                        {team.name}
                      </h5>
                      <p style={{
                        margin: 0,
                        fontSize: '13px',
                        color: 'var(--text-muted)',
                        fontWeight: '500'
                      }}>
                        {team.description || t('teamDescription', { ns: 'settings', defaultValue: 'Manage team permissions and members' })}
                      </p>
                    </div>
                  </div>
                  <div style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: '8px'
                  }}>
                    <span style={{
                      padding: '4px 10px',
                      backgroundColor: team.status === 'active' ? 'var(--success-bg)' : 'var(--error-bg)',
                      color: team.status === 'active' ? 'var(--success)' : 'var(--error)',
                      borderRadius: 'var(--radius-lg)',
                      fontSize: '11px',
                      fontWeight: '600',
                      textTransform: 'uppercase',
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: '4px'
                    }}>
                      <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>
                        {team.status === 'active' ? 'check_circle' : 'cancel'}
                      </span>
                      {team.status}
                    </span>
                  </div>
                </div>

                <div style={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'space-between',
                  fontSize: '13px',
                  color: 'var(--text-muted)',
                  gap: '20px',
                  marginTop: '16px'
                }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <div style={{
                      width: '32px',
                      height: '32px',
                      borderRadius: '8px',
                      backgroundColor: 'var(--success-bg)',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center'
                    }}>
                      <span className="material-symbols-outlined" style={{ fontSize: '18px', color: 'var(--success)' }}>
                        person
                      </span>
                    </div>
                    <div>
                      <div style={{ fontWeight: '600', color: 'var(--text-primary)' }}>
                        {team.member_count || 0}
                      </div>
                      <div style={{ fontSize: '11px' }}>
                        {t('members', { ns: 'settings', defaultValue: 'members' })}
                      </div>
                    </div>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <div style={{
                      width: '32px',
                      height: '32px',
                      borderRadius: '8px',
                      backgroundColor: 'var(--info-bg)',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center'
                    }}>
                      <span className="material-symbols-outlined" style={{ fontSize: '18px', color: 'var(--info)' }}>
                        lock
                      </span>
                    </div>
                    <div>
                      <div style={{ fontWeight: '600', color: 'var(--text-primary)' }}>
                        {team.page_access?.length || 0}
                      </div>
                      <div style={{ fontSize: '11px' }}>
                        {t('pages', { ns: 'settings', defaultValue: 'pages' })}
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Page Access Preview */}
              <div style={{
                padding: '20px',
                backgroundColor: 'var(--bg-tertiary)',
                borderTop: '1px solid var(--border-primary)'
              }}>
                <div style={{
                  display: 'flex',
                  flexWrap: 'wrap',
                  gap: '6px'
                }}>
                  {team.page_access?.slice(0, 4).map(pageId => {
                    const page = availablePages.find(p => p.id === pageId);
                    return page ? (
                      <span
                        key={pageId}
                        style={{
                          padding: '6px 12px',
                          backgroundColor: 'var(--success-bg)',
                          color: 'var(--success)',
                          borderRadius: '16px',
                          fontSize: '12px',
                          fontWeight: '600',
                          border: '1px solid var(--success)',
                          display: 'inline-flex',
                          alignItems: 'center',
                          gap: '4px'
                        }}
                      >
                        <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>
                          check_circle
                        </span>
                        {page.name}
                      </span>
                    ) : null;
                  })}
                  {team.page_access?.length > 4 && (
                    <span style={{
                      padding: '6px 12px',
                      backgroundColor: 'var(--bg-secondary)',
                      color: 'var(--text-muted)',
                      borderRadius: '16px',
                      fontSize: '12px',
                      fontWeight: '600',
                      fontStyle: 'italic'
                    }}>
                      +{team.page_access.length - 4} {t('more', { ns: 'settings', defaultValue: 'more' })}
                    </span>
                  )}
                  {(!team.page_access || team.page_access.length === 0) && (
                    <span style={{
                      padding: '6px 12px',
                      backgroundColor: 'var(--error-bg)',
                      color: 'var(--error)',
                      borderRadius: '16px',
                      fontSize: '12px',
                      fontWeight: '600',
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: '4px'
                    }}>
                      <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>
                        block
                      </span>
                      {t('noAccess', { ns: 'settings', defaultValue: 'No access' })}
                    </span>
                  )}
                </div>
              </div>
            </div>
          ))}

          {/* Empty State */}
          {teams.length === 0 && (
            <div style={{
              gridColumn: '1 / -1',
              padding: '48px 24px',
              textAlign: 'center',
              border: '2px dashed var(--border-primary)',
              borderRadius: 'var(--radius-lg)',
              backgroundColor: 'var(--bg-tertiary)'
            }}>
              <div style={{
                width: '80px',
                height: '80px',
                borderRadius: '50%',
                background: 'linear-gradient(135deg, var(--accent) 0%, var(--accent-hover) 100%)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                margin: '0 auto 20px',
                boxShadow: 'var(--shadow-md)'
              }}>
                <span className="material-symbols-outlined" style={{ fontSize: '40px', color: 'white' }}>
                  groups
                </span>
              </div>
              <h3 style={{
                margin: '0 0 8px 0',
                fontSize: '18px',
                fontWeight: '600',
                color: 'var(--text-primary)'
              }}>
                {t('noTeamsCreated', { ns: 'settings', defaultValue: 'No teams created yet' })}
              </h3>
              <p style={{
                margin: '0 0 20px 0',
                fontSize: '14px',
                color: 'var(--text-muted)'
              }}>
                {t('createFirstTeamDescription', { ns: 'settings', defaultValue: 'Create your first team to start managing members and permissions' })}
              </p>
              <button
                onClick={() => {
                  setTeamToEdit(null);
                  setShowTeamModal(true);
                }}
                style={{
                  padding: '12px 24px',
                  backgroundColor: 'var(--accent)',
                  color: 'var(--text-inverse)',
                  border: 'none',
                  borderRadius: 'var(--radius-md)',
                  fontSize: '14px',
                  fontWeight: '600',
                  cursor: 'pointer',
                  transition: 'all var(--transition-base)',
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '8px',
                  boxShadow: 'var(--shadow-sm)'
                }}
                onMouseEnter={(e) => {
                  e.target.style.backgroundColor = 'var(--accent-hover)';
                  e.target.style.boxShadow = 'var(--shadow-md)';
                  e.target.style.transform = 'translateY(-1px)';
                }}
                onMouseLeave={(e) => {
                  e.target.style.backgroundColor = 'var(--accent)';
                  e.target.style.boxShadow = 'var(--shadow-sm)';
                  e.target.style.transform = 'translateY(0)';
                }}
              >
                <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>add</span>
                {t('createYourFirstTeam', { ns: 'settings', defaultValue: 'Create Your First Team' })}
              </button>
            </div>
          )}
        </div>

        {/* Selected Team Details */}
        {selectedTeam && (
          <div style={{
            border: '1px solid var(--border-primary)',
            borderRadius: 'var(--radius-lg)',
            overflow: 'hidden',
            backgroundColor: 'var(--card)'
          }}>
            <div style={{
              padding: '20px',
              borderBottom: '1px solid var(--border-primary)',
              backgroundColor: 'var(--bg-tertiary)'
            }}>
              <div style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between'
              }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <span className="material-symbols-outlined" style={{ fontSize: '24px', color: 'var(--accent)' }}>
                    group
                  </span>
                  <h4 style={{
                    margin: 0,
                    fontSize: '18px',
                    fontWeight: '600',
                    color: 'var(--text-primary)'
                  }}>
                    {selectedTeam.name}
                  </h4>
                </div>
                <button
                  onClick={() => setSelectedTeam(null)}
                  style={{
                    padding: '8px',
                    background: 'none',
                    border: 'none',
                    color: 'var(--text-muted)',
                    cursor: 'pointer',
                    borderRadius: 'var(--radius-sm)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    transition: 'all var(--transition-base)'
                  }}
                  onMouseEnter={(e) => {
                    e.target.style.backgroundColor = 'var(--bg-hover)';
                    e.target.style.color = 'var(--text-primary)';
                  }}
                  onMouseLeave={(e) => {
                    e.target.style.backgroundColor = 'transparent';
                    e.target.style.color = 'var(--text-muted)';
                  }}
                >
                  <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>close</span>
                </button>
              </div>
            </div>

            <div style={{ padding: '24px' }}>
              {/* Team Actions */}
              <div style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
                marginBottom: '32px',
                padding: '20px',
                backgroundColor: 'var(--bg-tertiary)',
                borderRadius: '12px',
                border: '1px solid var(--border-primary)'
              }}>
                <h5 style={{
                  margin: 0,
                  fontSize: '18px',
                  fontWeight: '700',
                  color: 'var(--text-primary)',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '12px'
                }}>
                  <div style={{
                    width: '40px',
                    height: '40px',
                    borderRadius: '10px',
                    background: 'linear-gradient(135deg, var(--accent) 0%, var(--accent-hover) 100%)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    boxShadow: 'var(--shadow-sm)'
                  }}>
                    <span className="material-symbols-outlined" style={{ fontSize: '20px', color: 'white' }}>
                      settings
                    </span>
                  </div>
                  {t('teamSettings', { ns: 'settings', defaultValue: 'Team Settings' })}
                </h5>
                <div style={{ display: 'flex', gap: '16px' }}>
                  <button
                    onClick={() => {
                      setTeamToEdit(selectedTeam);
                      setShowTeamModal(true);
                    }}
                    style={{
                      padding: '12px 20px',
                      backgroundColor: 'var(--accent)',
                      color: 'white',
                      border: 'none',
                      borderRadius: '10px',
                      fontSize: '14px',
                      fontWeight: '600',
                      cursor: 'pointer',
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: '8px',
                      transition: 'all var(--transition-base)',
                      boxShadow: 'var(--shadow-sm)',
                      minWidth: '120px'
                    }}
                    onMouseEnter={(e) => {
                      e.target.style.backgroundColor = '#0056b3';
                      e.target.style.boxShadow = 'var(--shadow-md)';
                      e.target.style.transform = 'translateY(-2px)';
                      e.target.style.color = 'white';
                    }}
                    onMouseLeave={(e) => {
                      e.target.style.backgroundColor = 'var(--accent)';
                      e.target.style.boxShadow = 'var(--shadow-sm)';
                      e.target.style.transform = 'translateY(0)';
                      e.target.style.color = 'white';
                    }}
                  >
                    <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>edit</span>
                    {t('editTeam', { ns: 'settings', defaultValue: 'Edit Team' })}
                  </button>
                  <button
                    onClick={() => setShowMemberModal(true)}
                    style={{
                      padding: '12px 20px',
                      backgroundColor: 'var(--success)',
                      color: 'white',
                      border: 'none',
                      borderRadius: '10px',
                      fontSize: '14px',
                      fontWeight: '600',
                      cursor: 'pointer',
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: '8px',
                      transition: 'all var(--transition-base)',
                      boxShadow: 'var(--shadow-sm)',
                      minWidth: '140px'
                    }}
                    onMouseEnter={(e) => {
                      e.target.style.backgroundColor = '#218838';
                      e.target.style.boxShadow = 'var(--shadow-md)';
                      e.target.style.transform = 'translateY(-2px)';
                      e.target.style.color = 'white';
                    }}
                    onMouseLeave={(e) => {
                      e.target.style.backgroundColor = 'var(--success)';
                      e.target.style.boxShadow = 'var(--shadow-sm)';
                      e.target.style.transform = 'translateY(0)';
                      e.target.style.color = 'white';
                    }}
                  >
                    <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>person_add</span>
                    {t('addMember', { ns: 'settings', defaultValue: 'Add Member' })}
                  </button>
                </div>
              </div>

              {/* Team Member Password Information */}
              <div style={{
                marginBottom: '32px',
                padding: '20px',
                backgroundColor: 'var(--info-bg, #e3f2fd)',
                border: '1px solid var(--info-border, #2196f3)',
                borderRadius: '12px'
              }}>
                <div style={{
                  display: 'flex',
                  alignItems: 'flex-start',
                  gap: '16px'
                }}>
                  <div style={{
                    width: '40px',
                    height: '40px',
                    borderRadius: '10px',
                    backgroundColor: 'var(--info, #2196f3)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    flexShrink: 0
                  }}>
                    <span className="material-symbols-outlined" style={{ fontSize: '20px', color: 'white' }}>
                      info
                    </span>
                  </div>
                  <div style={{ flex: 1 }}>
                    <h6 style={{
                      margin: '0 0 12px 0',
                      fontSize: '16px',
                      fontWeight: '600',
                      color: 'var(--info-text, #1976d2)'
                    }}>
                      {t('teamMemberPasswordInfo', { ns: 'settings', defaultValue: 'Team Member Login Information' })}
                    </h6>
                    <div style={{
                      fontSize: '14px',
                      lineHeight: '1.6',
                      color: 'var(--text-primary)'
                    }}>
                      <p style={{ margin: '0 0 8px 0' }}>
                        <strong>{t('defaultPassword', { ns: 'settings', defaultValue: 'Default Password:' })}</strong> 
                        <code style={{
                          backgroundColor: 'var(--bg-secondary)',
                          padding: '4px 8px',
                          borderRadius: '4px',
                          fontFamily: 'monospace',
                          fontSize: '14px',
                          margin: '0 8px',
                          border: '1px solid var(--border-primary)'
                        }}>123456</code>
                      </p>
                      <p style={{ margin: '0 0 8px 0' }}>
                        {t('teamMemberPasswordInstructions', { ns: 'settings', defaultValue: 'All newly created team members can login with the default password above. They should change this password for security.' })}
                      </p>
                      <p style={{ margin: '0' }}>
                        <strong>{t('howToChangePassword', { ns: 'settings', defaultValue: 'How to change password:' })}</strong> {t('goToSecuritySettings', { ns: 'settings', defaultValue: 'Go to Security settings to change the password, or use the "Forgot Password" option on the login page.' })}
                      </p>
                    </div>
                  </div>
                </div>
              </div>

              {/* Page Access Display (Read-only) */}
              <div data-tour="settings-team-permissions" style={{ marginBottom: '32px' }}>
                <h6 style={{
                  margin: '0 0 16px 0',
                  fontSize: '14px',
                  fontWeight: '600',
                  color: 'var(--text-primary)',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <span className="material-symbols-outlined" style={{ fontSize: '18px', color: 'var(--accent)' }}>
                    lock
                  </span>
                  {t('pageAccessPermissions', { ns: 'settings', defaultValue: 'Page Access Permissions' })}
                </h6>
                <div style={{
                  padding: '16px',
                  border: '1px solid var(--border-primary)',
                  borderRadius: '8px',
                  backgroundColor: 'var(--bg-tertiary)'
                }}>
                  {selectedTeam.page_access && selectedTeam.page_access.length > 0 ? (
                    <div style={{
                      display: 'flex',
                      flexWrap: 'wrap',
                      gap: '8px'
                    }}>
                      {selectedTeam.page_access.map(pageId => {
                        const page = availablePages.find(p => p.id === pageId);
                        if (!page) {return null;}
                        return (
                          <div
                            key={pageId}
                            style={{
                              padding: '8px 12px',
                              backgroundColor: 'var(--success-bg)',
                              color: 'var(--success)',
                              borderRadius: '6px',
                              fontSize: '13px',
                              fontWeight: '500',
                              border: '1px solid var(--success)',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '6px'
                            }}
                          >
                            <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>
                              check_circle
                            </span>
                            {page.name}
                          </div>
                        );
                      })}
                    </div>
                  ) : (
                    <p style={{
                      margin: 0,
                      color: 'var(--text-muted)',
                      fontSize: '14px',
                      fontStyle: 'italic'
                    }}>
                      {t('noPageAccess', { ns: 'settings', defaultValue: 'No page access permissions assigned' })}
                    </p>
                  )}
                </div>
              </div>

              {/* Team Members */}
              <div data-tour="settings-team-members">
                <TeamMemberList
                  businessId={businessId}
                  teamId={selectedTeam.id}
                  onMemberRemoved={handleMemberRemoved}
                />
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Modals */}
      <TeamCreationModal
        isOpen={showTeamModal}
        onClose={() => setShowTeamModal(false)}
        businessId={businessId}
        onTeamCreated={handleCreateTeam}
        teamToEdit={teamToEdit}
        onTeamUpdated={handleTeamUpdated}
      />

      <AddTeamMemberModal
        isOpen={showMemberModal}
        onClose={() => setShowMemberModal(false)}
        businessId={businessId}
        teamId={selectedTeam?.id}
        onMemberAdded={handleMemberAdded}
      />

      {/* Floating Action Buttons for Mobile */}
      {isMobile && (
        <>
          {/* Floating Create Team Button */}
          <button
            onClick={() => {
              setTeamToEdit(null);
              setShowTeamModal(true);
            }}
            style={{
              position: 'fixed',
              bottom: '20px',
              right: '20px',
              width: '56px',
              height: '56px',
              borderRadius: '50%',
              backgroundColor: 'var(--accent)',
              color: 'white',
              border: 'none',
              boxShadow: 'var(--shadow-lg)',
              cursor: 'pointer',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              zIndex: 1000,
              transition: 'all var(--transition-base)'
            }}
            onMouseEnter={(e) => {
              e.target.style.backgroundColor = '#0056b3';
              e.target.style.transform = 'scale(1.1)';
              e.target.style.boxShadow = 'var(--shadow-xl)';
              e.target.style.color = 'white';
            }}
            onMouseLeave={(e) => {
              e.target.style.backgroundColor = 'var(--accent)';
              e.target.style.transform = 'scale(1)';
              e.target.style.boxShadow = 'var(--shadow-lg)';
              e.target.style.color = 'white';
            }}
          >
            <span className="material-symbols-outlined" style={{ fontSize: '24px' }}>
              add
            </span>
          </button>

          {/* Floating Add Member Button (only when team is selected) */}
          {selectedTeam && (
            <button
              onClick={() => setShowMemberModal(true)}
              style={{
                position: 'fixed',
                bottom: '20px',
                right: '90px',
                width: '56px',
                height: '56px',
                borderRadius: '50%',
                backgroundColor: 'var(--success)',
                color: 'white',
                border: 'none',
                boxShadow: 'var(--shadow-lg)',
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                zIndex: 1000,
                transition: 'all var(--transition-base)'
              }}
              onMouseEnter={(e) => {
                e.target.style.backgroundColor = '#218838';
                e.target.style.transform = 'scale(1.1)';
                e.target.style.boxShadow = 'var(--shadow-xl)';
                e.target.style.color = 'white';
              }}
              onMouseLeave={(e) => {
                e.target.style.backgroundColor = 'var(--success)';
                e.target.style.transform = 'scale(1)';
                e.target.style.boxShadow = 'var(--shadow-lg)';
                e.target.style.color = 'white';
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: '24px' }}>
                person_add
              </span>
            </button>
          )}
        </>
      )}
    </div>
  );
};

export default Team;
